const narutoQuestions = [
  {t:"m",q:"\u00bfCu\u00e1l es el sue\u00f1o principal de Naruto Uzumaki al inicio de la serie?",o:["Convertirse en Hokage", "Ser el ninja m\u00e1s rico", "Destruir Konoha", "Unirse a Akatsuki"],a:0,exp:"Naruto sue\u00f1a con convertirse en Hokage para que toda la aldea lo reconozca.",extra:"Su deseo nace de la soledad y el rechazo que sufri\u00f3 por tener al Kyubi sellado dentro. Con el tiempo, ese sue\u00f1o madura: ya no busca solo reconocimiento, sino proteger a todos."},
  {t:"m",q:"\u00bfQu\u00e9 bestia con cola est\u00e1 sellada dentro de Naruto?",o:["Shukaku", "Kurama", "Gyuki", "Matatabi"],a:1,exp:"Kurama, el Zorro de Nueve Colas, est\u00e1 sellado dentro de Naruto.",extra:"Durante gran parte de la historia, Naruto y Kurama tienen una relaci\u00f3n de conflicto. M\u00e1s adelante desarrollan confianza y se convierten en compa\u00f1eros reales de batalla."},
  {t:"m",q:"\u00bfQui\u00e9n sell\u00f3 al Kyubi dentro de Naruto?",o:["Hiruzen Sarutobi", "Minato Namikaze", "Jiraiya", "Kakashi Hatake"],a:1,exp:"Minato Namikaze, el Cuarto Hokage, sell\u00f3 al Kyubi dentro de Naruto usando un jutsu de sellado.",extra:"Minato era el padre de Naruto. La decisi\u00f3n fue tr\u00e1gica pero tambi\u00e9n esperanzadora: crey\u00f3 que Naruto podr\u00eda dominar ese poder y salvar el futuro."},
  {t:"m",q:"\u00bfQui\u00e9n es la madre de Naruto?",o:["Kushina Uzumaki", "Tsunade Senju", "Mikoto Uchiha", "Kurenai Yuhi"],a:0,exp:"La madre de Naruto es Kushina Uzumaki.",extra:"Kushina tambi\u00e9n fue jinchuriki de Kurama antes que Naruto. Su linaje Uzumaki explica la enorme vitalidad y capacidad de chakra de Naruto."},
  {t:"m",q:"\u00bfCu\u00e1l es el equipo ninja inicial de Naruto?",o:["Equipo 7", "Equipo 8", "Equipo 10", "Equipo Guy"],a:0,exp:"Naruto forma parte del Equipo 7 junto a Sasuke, Sakura y Kakashi.",extra:"El Equipo 7 es el n\u00facleo emocional de la serie. Sus fracturas y reconciliaciones sostienen buena parte del desarrollo de Naruto y Sasuke."},
  {t:"m",q:"\u00bfQui\u00e9n es el maestro del Equipo 7?",o:["Might Guy", "Asuma Sarutobi", "Kakashi Hatake", "Iruka Umino"],a:2,exp:"Kakashi Hatake es el sensei del Equipo 7.",extra:"Kakashi hereda muchas lecciones de su propio pasado con Obito y Rin. Su forma de ense\u00f1ar pone el trabajo en equipo por encima de las reglas r\u00edgidas."},
  {t:"m",q:"\u00bfQu\u00e9 examen deben superar Naruto, Sasuke y Sakura para convertirse oficialmente en genin bajo Kakashi?",o:["Robar campanas", "Derrotar a Zabuza", "Pasar el Bosque de la Muerte", "Firmar un contrato de invocaci\u00f3n"],a:0,exp:"Kakashi les hace la prueba de las campanas para evaluar su trabajo en equipo.",extra:"El verdadero objetivo no era que cada uno consiguiera una campana, sino que aprendieran a colaborar. Es una lecci\u00f3n que Kakashi recibi\u00f3 de Obito."},
  {t:"m",q:"\u00bfCu\u00e1l es el jutsu caracter\u00edstico de Naruto al inicio?",o:["Chidori", "Rasengan", "Kage Bunshin no Jutsu", "Amaterasu"],a:2,exp:"Naruto usa masivamente el Kage Bunshin no Jutsu, o T\u00e9cnica de Clones de Sombra.",extra:"A diferencia de clones ilusorios, los clones de sombra son cuerpos reales de chakra. Naruto puede crear muchos por su enorme reserva de energ\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica aprende Naruto de Jiraiya?",o:["Rasengan", "Chidori", "Byakugan", "Reanimaci\u00f3n Impura"],a:0,exp:"Naruto aprende el Rasengan gracias al entrenamiento de Jiraiya.",extra:"El Rasengan fue creado por Minato, el padre de Naruto. Esto hace que la t\u00e9cnica conecte a Naruto con su herencia sin que \u00e9l lo sepa al principio."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 originalmente el Rasengan?",o:["Jiraiya", "Minato Namikaze", "Kakashi Hatake", "Tobirama Senju"],a:1,exp:"Minato Namikaze cre\u00f3 el Rasengan inspir\u00e1ndose en la Bola Bestia con Cola.",extra:"Minato nunca lleg\u00f3 a completar la t\u00e9cnica con una naturaleza elemental. Naruto m\u00e1s tarde la evoluciona con viento para crear el Rasen Shuriken."},
  {t:"m",q:"\u00bfCu\u00e1l es la naturaleza de chakra principal de Naruto?",o:["Fuego", "Rayo", "Viento", "Agua"],a:2,exp:"La naturaleza elemental principal de Naruto es viento.",extra:"Esto le permite desarrollar el F\u016bton: Rasen Shuriken, una t\u00e9cnica devastadora que ataca a nivel celular."},
  {t:"m",q:"\u00bfQu\u00e9 clan posee el Sharingan?",o:["Hyuga", "Uchiha", "Nara", "Akimichi"],a:1,exp:"El Sharingan es el d\u014djutsu caracter\u00edstico del clan Uchiha.",extra:"El Sharingan permite copiar t\u00e9cnicas, leer movimientos y usar genjutsu. Sus formas avanzadas tienen costes emocionales y f\u00edsicos enormes."},
  {t:"m",q:"\u00bfQui\u00e9n es el hermano mayor de Sasuke?",o:["Shisui Uchiha", "Itachi Uchiha", "Madara Uchiha", "Obito Uchiha"],a:1,exp:"Itachi Uchiha es el hermano mayor de Sasuke.",extra:"Sasuke cree durante a\u00f1os que Itachi masacr\u00f3 al clan por crueldad, pero la verdad revela una tragedia pol\u00edtica mucho m\u00e1s compleja."},
  {t:"m",q:"\u00bfQu\u00e9 clan fue masacrado antes del inicio de la serie?",o:["Clan Hyuga", "Clan Uchiha", "Clan Nara", "Clan Aburame"],a:1,exp:"El clan Uchiha fue masacrado, dejando a Sasuke como uno de los pocos sobrevivientes.",extra:"La masacre Uchiha es uno de los grandes traumas pol\u00edticos de Naruto. Est\u00e1 ligada a Danzo, Konoha, Itachi y el miedo a un golpe de Estado."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica caracter\u00edstica usa Sasuke con chakra de rayo?",o:["Rasengan", "Chidori", "Kaiten", "Baika no Jutsu"],a:1,exp:"Sasuke aprende el Chidori de Kakashi.",extra:"El Chidori requiere gran velocidad y precisi\u00f3n. Sin Sharingan, su uso es muy peligroso porque el usuario puede no ver bien el contraataque enemigo."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 el Chidori?",o:["Sasuke", "Kakashi", "Minato", "Orochimaru"],a:1,exp:"Kakashi cre\u00f3 el Chidori cuando era joven.",extra:"M\u00e1s tarde desarrolla variantes como el Raikiri. La t\u00e9cnica se convierte en s\u00edmbolo tanto de Kakashi como de Sasuke."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es famoso por decir \u201cDattebayo\u201d en japon\u00e9s?",o:["Naruto", "Sasuke", "Kakashi", "Shikamaru"],a:0,exp:"Naruto usa frecuentemente la muletilla \u201cDattebayo\u201d.",extra:"En doblajes se adapta de distintas formas. Sirve para darle una voz impulsiva, testaruda y juvenil."},
  {t:"m",q:"\u00bfQui\u00e9n es el primer maestro que reconoce sinceramente a Naruto?",o:["Iruka Umino", "Kakashi Hatake", "Jiraiya", "Hiruzen"],a:0,exp:"Iruka es el primer adulto que reconoce el valor de Naruto y lo protege.",extra:"La escena en la que Iruka defiende a Naruto de Mizuki es fundamental: Naruto descubre que no est\u00e1 completamente solo."},
  {t:"m",q:"\u00bfQui\u00e9n enga\u00f1a a Naruto para robar el pergamino prohibido al inicio?",o:["Mizuki", "Zabuza", "Kabuto", "Orochimaru"],a:0,exp:"Mizuki manipula a Naruto para que robe el pergamino de t\u00e9cnicas prohibidas.",extra:"Gracias a ese incidente, Naruto aprende el Kage Bunshin no Jutsu y demuestra su potencial."},
  {t:"m",q:"\u00bfQui\u00e9n es el primer gran enemigo del arco del Pa\u00eds de las Olas?",o:["Zabuza Momochi", "Gaara", "Orochimaru", "Kimimaro"],a:0,exp:"Zabuza Momochi es el principal enemigo del arco del Pa\u00eds de las Olas.",extra:"Zabuza introduce el tono m\u00e1s duro del mundo ninja: mercenarios, guerras, ni\u00f1os usados como armas y v\u00ednculos ocultos bajo brutalidad."},
  {t:"m",q:"\u00bfQui\u00e9n acompa\u00f1a a Zabuza como arma humana y compa\u00f1ero leal?",o:["Haku", "Suigetsu", "Kimimaro", "Kabuto"],a:0,exp:"Haku acompa\u00f1a a Zabuza y posee un kekkei genkai de hielo.",extra:"Haku es uno de los personajes tr\u00e1gicos tempranos de Naruto. Su lealtad a Zabuza y su deseo de ser \u00fatil marcan profundamente a Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 kekkei genkai usa Haku?",o:["Hielo", "Madera", "Lava", "Polvo"],a:0,exp:"Haku usa Hy\u014dton, o elemento hielo, combinando agua y viento.",extra:"Sus espejos de hielo demon\u00edacos son una t\u00e9cnica veloz y letal que supera al Equipo 7 en su primera gran misi\u00f3n real."},
  {t:"m",q:"\u00bfQu\u00e9 puente termina llevando el nombre de Naruto?",o:["Puente del Gran Naruto", "Puente Uzumaki", "Puente del Hokage", "Puente de Konoha"],a:0,exp:"El puente del Pa\u00eds de las Olas es nombrado Gran Puente Naruto.",extra:"El nombre simboliza c\u00f3mo Naruto inspir\u00f3 a Inari y a la gente del pa\u00eds a resistir contra Gato."},
  {t:"m",q:"\u00bfQu\u00e9 examen re\u00fane a ninjas de varias aldeas en la primera parte?",o:["Examen Chunin", "Examen Jonin", "Examen ANBU", "Examen Kage"],a:0,exp:"El Examen Chunin re\u00fane a genin de distintas aldeas para evaluar ascensos.",extra:"El examen funciona como torneo, prueba psicol\u00f3gica y escenario pol\u00edtico. Tambi\u00e9n introduce a muchos personajes centrales como Gaara, Lee, Neji y Orochimaru."},
  {t:"m",q:"\u00bfQu\u00e9 equipo est\u00e1 formado por Shikamaru, Ino y Choji?",o:["Equipo 8", "Equipo 10", "Equipo Guy", "Equipo 7"],a:1,exp:"Shikamaru, Ino y Choji forman el Equipo 10 bajo Asuma.",extra:"Este tr\u00edo hereda la formaci\u00f3n Ino-Shika-Cho, una tradici\u00f3n de sus clanes basada en control mental, sombras y expansi\u00f3n corporal."},
  {t:"m",q:"\u00bfQu\u00e9 clan controla sombras?",o:["Nara", "Yamanaka", "Akimichi", "Aburame"],a:0,exp:"El clan Nara usa t\u00e9cnicas de sombra.",extra:"Shikamaru convierte estas t\u00e9cnicas en herramientas estrat\u00e9gicas brillantes, compensando su falta de entusiasmo con una mente excepcional."},
  {t:"m",q:"\u00bfQu\u00e9 clan usa t\u00e9cnicas de posesi\u00f3n mental?",o:["Yamanaka", "Nara", "Akimichi", "Inuzuka"],a:0,exp:"El clan Yamanaka usa t\u00e9cnicas mentales como transferencia de conciencia.",extra:"Ino usa estas habilidades para espionaje, comunicaci\u00f3n y control, especialmente en coordinaci\u00f3n con Shikamaru y Choji."},
  {t:"m",q:"\u00bfQu\u00e9 clan usa t\u00e9cnicas de expansi\u00f3n corporal?",o:["Akimichi", "Aburame", "Hyuga", "Sarutobi"],a:0,exp:"El clan Akimichi usa t\u00e9cnicas que expanden partes o todo el cuerpo.",extra:"Choji convierte calor\u00edas en chakra para aumentar su poder f\u00edsico. Su clan trata la comida como parte real de su estilo ninja."},
  {t:"m",q:"\u00bfQu\u00e9 clan usa insectos como parte de su cuerpo y combate?",o:["Aburame", "Inuzuka", "Hyuga", "Nara"],a:0,exp:"El clan Aburame vive en simbiosis con insectos que usan para rastreo y combate.",extra:"Shino Aburame es uno de los ninjas m\u00e1s discretos pero efectivos de su generaci\u00f3n, con t\u00e9cnicas dif\u00edciles de contrarrestar."},
  {t:"m",q:"\u00bfQu\u00e9 clan combate junto a perros ninja?",o:["Inuzuka", "Aburame", "Yamanaka", "Hatake"],a:0,exp:"El clan Inuzuka pelea junto a compa\u00f1eros caninos.",extra:"Kiba y Akamaru son el ejemplo m\u00e1s visible. Sus t\u00e9cnicas combinan olfato, velocidad y ataques coordinados."},
  {t:"m",q:"\u00bfQu\u00e9 d\u014djutsu posee el clan Hyuga?",o:["Sharingan", "Byakugan", "Rinnegan", "Jogan"],a:1,exp:"El clan Hyuga posee el Byakugan.",extra:"El Byakugan permite visi\u00f3n casi de 360 grados y ver el sistema de chakra. Es la base del estilo Pu\u00f1o Suave."},
  {t:"m",q:"\u00bfQu\u00e9 estilo de combate usa el clan Hyuga?",o:["Pu\u00f1o Suave", "Pu\u00f1o Fuerte", "Estilo Sombra", "Taijutsu Borracho"],a:0,exp:"Los Hyuga usan el Pu\u00f1o Suave para atacar el sistema de chakra.",extra:"Aunque parece elegante, es extremadamente peligroso porque puede cerrar tenketsu y da\u00f1ar \u00f3rganos internos."},
  {t:"m",q:"\u00bfQui\u00e9n es primo de Hinata y genio del clan Hyuga?",o:["Neji Hyuga", "Kiba Inuzuka", "Shino Aburame", "Rock Lee"],a:0,exp:"Neji Hyuga es primo de Hinata y prodigio de la rama secundaria del clan.",extra:"Su historia explora el destino impuesto por el sistema de ramas del clan Hyuga y c\u00f3mo Naruto desaf\u00eda esa visi\u00f3n fatalista."},
  {t:"m",q:"\u00bfQu\u00e9 personaje no puede usar ninjutsu ni genjutsu de forma efectiva?",o:["Rock Lee", "Neji", "Shino", "Kiba"],a:0,exp:"Rock Lee no puede usar ninjutsu ni genjutsu de manera efectiva y se especializa en taijutsu.",extra:"Lee representa esfuerzo puro. Su pelea contra Gaara es una de las m\u00e1s queridas porque demuestra hasta d\u00f3nde puede llegar alguien sin talento natural tradicional."},
  {t:"m",q:"\u00bfQui\u00e9n es el maestro de Rock Lee?",o:["Might Guy", "Kakashi", "Asuma", "Kurenai"],a:0,exp:"Might Guy es el maestro de Rock Lee.",extra:"Guy ve en Lee una versi\u00f3n de s\u00ed mismo y lo entrena con disciplina extrema, entusiasmo desbordado y fe absoluta en el trabajo duro."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica extrema abre limitadores del cuerpo?",o:["Ocho Puertas Internas", "Rasengan", "Chidori", "Amaterasu"],a:0,exp:"Las Ocho Puertas Internas liberan l\u00edmites f\u00edsicos del cuerpo a cambio de gran da\u00f1o.",extra:"Abrir la Octava Puerta otorga un poder monstruoso pero normalmente cuesta la vida. Guy la usa contra Madara en la guerra."},
  {t:"m",q:"\u00bfContra qui\u00e9n tiene Rock Lee su pelea m\u00e1s famosa en los Ex\u00e1menes Chunin?",o:["Gaara", "Sasuke", "Naruto", "Neji"],a:0,exp:"Rock Lee pelea contra Gaara en una de las batallas m\u00e1s recordadas de la serie.",extra:"La escena en la que Lee suelta sus pesas revela su velocidad real y se volvi\u00f3 ic\u00f3nica dentro del anime."},
  {t:"m",q:"\u00bfQu\u00e9 bestia con cola estaba sellada dentro de Gaara?",o:["Shukaku", "Kurama", "Isobu", "Saiken"],a:0,exp:"Gaara era jinchuriki de Shukaku, el Una Cola.",extra:"Como Naruto, Gaara sufri\u00f3 rechazo y soledad, pero tom\u00f3 un camino m\u00e1s oscuro hasta que Naruto lo confront\u00f3 emocionalmente."},
  {t:"m",q:"\u00bfDe qu\u00e9 aldea proviene Gaara?",o:["Aldea de la Arena", "Aldea de la Niebla", "Aldea de la Roca", "Aldea de la Nube"],a:0,exp:"Gaara proviene de Sunagakure, la Aldea Oculta de la Arena.",extra:"M\u00e1s adelante se convierte en Kazekage, pasando de arma temida a l\u00edder amado por su pueblo."},
  {t:"m",q:"\u00bfQui\u00e9nes son los hermanos de Gaara?",o:["Temari y Kankuro", "Ino y Choji", "Sasori y Deidara", "Karin y Suigetsu"],a:0,exp:"Temari y Kankuro son hermanos de Gaara.",extra:"Temari usa un abanico gigante y t\u00e9cnicas de viento, mientras Kankuro usa marionetas, una especialidad de la Arena."},
  {t:"m",q:"\u00bfQu\u00e9 villano infiltra los Ex\u00e1menes Chunin disfrazado?",o:["Orochimaru", "Itachi", "Kisame", "Sasori"],a:0,exp:"Orochimaru se infiltra en los Ex\u00e1menes Chunin y marca a Sasuke con el sello maldito.",extra:"Orochimaru introduce el miedo a una amenaza de nivel Sannin y se convierte en una tentaci\u00f3n de poder para Sasuke."},
  {t:"m",q:"\u00bfQu\u00e9 sello otorga Orochimaru a Sasuke?",o:["Sello Maldito del Cielo", "Sello de los Ocho Trigramas", "Sello Reaper", "Sello Byakugo"],a:0,exp:"Orochimaru marca a Sasuke con el Sello Maldito del Cielo.",extra:"El sello aumenta su poder pero tambi\u00e9n lo corrompe, alimentando su deseo de abandonar Konoha para volverse m\u00e1s fuerte."},
  {t:"m",q:"\u00bfQu\u00e9 Hokage muere durante la invasi\u00f3n de Konoha?",o:["Primer Hokage", "Segundo Hokage", "Tercer Hokage", "Cuarto Hokage"],a:2,exp:"Hiruzen Sarutobi, el Tercer Hokage, muere enfrentando a Orochimaru.",extra:"Su muerte marca el fin de una era para Konoha y muestra el costo de sus decisiones pasadas como maestro de Orochimaru."},
  {t:"m",q:"\u00bfQui\u00e9nes son los tres Sannin legendarios?",o:["Jiraiya, Tsunade y Orochimaru", "Kakashi, Guy y Asuma", "Minato, Kushina y Fugaku", "Hashirama, Tobirama y Hiruzen"],a:0,exp:"Los tres Sannin son Jiraiya, Tsunade y Orochimaru.",extra:"Recibieron ese t\u00edtulo por sobrevivir a Hanzo de la Salamandra. Cada uno entrenar\u00eda a un miembro del nuevo Equipo 7 de forma simb\u00f3lica."},
  {t:"m",q:"\u00bfQui\u00e9n entrena a Naruto durante el salto temporal?",o:["Jiraiya", "Kakashi", "Iruka", "Yamato"],a:0,exp:"Jiraiya entrena a Naruto durante los a\u00f1os entre Naruto y Naruto Shippuden.",extra:"Adem\u00e1s de ense\u00f1arle t\u00e9cnicas, Jiraiya se convierte en una figura paterna para Naruto."},
  {t:"m",q:"\u00bfQui\u00e9n entrena a Sakura en medicina y fuerza f\u00edsica?",o:["Tsunade", "Kurenai", "Anko", "Shizune"],a:0,exp:"Tsunade entrena a Sakura como ninja m\u00e9dica y combatiente de fuerza monstruosa.",extra:"Sakura hereda de Tsunade el control preciso de chakra, la fuerza amplificada y m\u00e1s tarde el sello Byakugo."},
  {t:"m",q:"\u00bfQui\u00e9n entrena a Sasuke tras abandonar Konoha?",o:["Orochimaru", "Itachi", "Madara", "Kakashi"],a:0,exp:"Sasuke entrena con Orochimaru buscando poder para matar a Itachi.",extra:"Sasuke no conf\u00eda realmente en Orochimaru; lo usa como medio para alcanzar su venganza."},
  {t:"m",q:"\u00bfQu\u00e9 cargo asume Tsunade despu\u00e9s de la muerte del Tercer Hokage?",o:["Quinta Hokage", "Cuarta Kazekage", "L\u00edder ANBU", "Consejera del Daimyo"],a:0,exp:"Tsunade se convierte en la Quinta Hokage.",extra:"Aunque al principio rechaza el cargo por trauma y cinismo, Naruto la inspira a recuperar la fe en el sue\u00f1o de ser Hokage."},
  {t:"m",q:"\u00bfQu\u00e9 fobia sufre Tsunade por sus p\u00e9rdidas pasadas?",o:["Hemofobia", "Claustrofobia", "Miedo al fuego", "Miedo al agua"],a:0,exp:"Tsunade sufre hemofobia, miedo a la sangre, por traumas relacionados con la muerte de seres queridos.",extra:"Su recuperaci\u00f3n emocional ocurre durante el arco de b\u00fasqueda de Tsunade, cuando decide volver a luchar y proteger Konoha."},
  {t:"m",q:"\u00bfQu\u00e9 organizaci\u00f3n criminal caza jinchuriki?",o:["Akatsuki", "ANBU", "Ra\u00edz", "Siete Espadachines"],a:0,exp:"Akatsuki busca capturar a los jinchuriki para extraer sus bestias con cola.",extra:"Aunque inicialmente parece una organizaci\u00f3n de villanos, su origen est\u00e1 ligado a ideales de paz distorsionados por guerra, p\u00e9rdida y manipulaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 prenda caracteriza a Akatsuki?",o:["Capa negra con nubes rojas", "Armadura samur\u00e1i blanca", "M\u00e1scara ANBU", "T\u00fanica de Hokage"],a:0,exp:"Akatsuki es reconocible por sus capas negras con nubes rojas.",extra:"Las nubes rojas simbolizan la lluvia de sangre en Amegakure, conectando su est\u00e9tica con el dolor de la guerra."},
  {t:"m",q:"\u00bfQui\u00e9nes capturan a Gaara al inicio de Shippuden?",o:["Deidara y Sasori", "Itachi y Kisame", "Hidan y Kakuzu", "Pain y Konan"],a:0,exp:"Deidara y Sasori capturan a Gaara para extraer a Shukaku.",extra:"Este arco muestra inmediatamente la amenaza real de Akatsuki y cu\u00e1nto ha cambiado la escala desde la primera parte."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki usa arcilla explosiva?",o:["Deidara", "Sasori", "Kakuzu", "Hidan"],a:0,exp:"Deidara usa arcilla explosiva moldeada con bocas en sus manos.",extra:"Deidara considera sus explosiones una forma de arte ef\u00edmero, en contraste con Sasori, que cree en el arte eterno."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki convierte cuerpos en marionetas?",o:["Sasori", "Deidara", "Kisame", "Zetsu"],a:0,exp:"Sasori es un maestro titiritero que convierte personas en marionetas humanas.",extra:"Su obsesi\u00f3n por el arte eterno lo lleva incluso a convertir su propio cuerpo en marioneta."},
  {t:"m",q:"\u00bfQui\u00e9n derrota a Sasori?",o:["Sakura y Chiyo", "Naruto y Kakashi", "Gaara y Temari", "Sai y Yamato"],a:0,exp:"Sakura y Chiyo derrotan a Sasori en una batalla de venenos, marionetas y fuerza bruta.",extra:"La pelea es un gran momento para Sakura, mostrando el resultado de su entrenamiento con Tsunade."},
  {t:"m",q:"\u00bfQu\u00e9 nuevo miembro reemplaza a Sasuke temporalmente en el Equipo 7?",o:["Sai", "Shino", "Neji", "Kiba"],a:0,exp:"Sai se une al Equipo 7 durante Shippuden.",extra:"Sai viene de Ra\u00edz y debe aprender emociones, v\u00ednculos y comunicaci\u00f3n real con Naruto y Sakura."},
  {t:"m",q:"\u00bfQui\u00e9n lidera el Equipo 7 cuando Kakashi no puede hacerlo en Shippuden?",o:["Yamato", "Asuma", "Guy", "Ibiki"],a:0,exp:"Yamato lidera temporalmente el Equipo 7.",extra:"Yamato posee c\u00e9lulas de Hashirama y puede usar Mokuton, lo que lo hace \u00fatil para contener el chakra de Kurama."},
  {t:"m",q:"\u00bfQu\u00e9 elemento avanzado usa Yamato?",o:["Madera", "Hielo", "Lava", "Polvo"],a:0,exp:"Yamato puede usar Mokuton, el elemento madera.",extra:"El Mokuton es extremadamente raro y est\u00e1 asociado principalmente con Hashirama Senju, el Primer Hokage."},
  {t:"m",q:"\u00bfQui\u00e9n fue el Primer Hokage?",o:["Hashirama Senju", "Tobirama Senju", "Hiruzen Sarutobi", "Minato Namikaze"],a:0,exp:"Hashirama Senju fue el Primer Hokage y fundador de Konoha junto a Madara.",extra:"Hashirama era conocido como el Dios de los Shinobi por su poder inmenso y su habilidad \u00fanica con Mokuton."},
  {t:"m",q:"\u00bfQui\u00e9n fue el Segundo Hokage?",o:["Tobirama Senju", "Hashirama Senju", "Hiruzen Sarutobi", "Danzo Shimura"],a:0,exp:"Tobirama Senju fue el Segundo Hokage.",extra:"Tobirama cre\u00f3 muchas instituciones y t\u00e9cnicas importantes, como la Academia Ninja, el Edo Tensei y el Hiraishin."},
  {t:"m",q:"\u00bfQui\u00e9n fue el Cuarto Hokage?",o:["Minato Namikaze", "Kakashi Hatake", "Jiraiya", "Fugaku Uchiha"],a:0,exp:"Minato Namikaze fue el Cuarto Hokage.",extra:"Fue conocido como el Rel\u00e1mpago Amarillo de Konoha por su velocidad y uso del Hiraishin."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica de teletransporte hizo famoso a Minato?",o:["Hiraishin", "Kamui", "Shunshin", "Amenotejikara"],a:0,exp:"Minato usaba el Hiraishin, la T\u00e9cnica del Dios Trueno Volador.",extra:"Marcaba lugares u objetos con sellos y pod\u00eda teletransportarse instant\u00e1neamente a ellos."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki usa rituales de inmortalidad y una guada\u00f1a?",o:["Hidan", "Kakuzu", "Kisame", "Deidara"],a:0,exp:"Hidan es un fan\u00e1tico de Jashin con inmortalidad ritual.",extra:"Su t\u00e9cnica requiere sangre del enemigo y un c\u00edrculo ritual. Es letal porque comparte da\u00f1o con su v\u00edctima."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki tiene m\u00faltiples corazones?",o:["Kakuzu", "Hidan", "Pain", "Zetsu"],a:0,exp:"Kakuzu posee varios corazones robados, lo que le permite usar m\u00faltiples naturalezas de chakra.",extra:"Su obsesi\u00f3n por el dinero y su longevidad lo convierten en uno de los miembros m\u00e1s pragm\u00e1ticos de Akatsuki."},
  {t:"m",q:"\u00bfQui\u00e9n mata a Asuma Sarutobi?",o:["Hidan", "Kakuzu", "Pain", "Itachi"],a:0,exp:"Asuma muere por la t\u00e9cnica ritual de Hidan.",extra:"Su muerte impulsa el crecimiento de Shikamaru, quien dise\u00f1a una venganza estrat\u00e9gica contra Hidan."},
  {t:"m",q:"\u00bfQui\u00e9n derrota finalmente a Hidan?",o:["Shikamaru", "Naruto", "Kakashi", "Choji"],a:0,exp:"Shikamaru derrota a Hidan usando una trampa preparada en el bosque de su clan.",extra:"No puede matarlo de forma convencional por su inmortalidad, as\u00ed que lo desmembra y lo entierra vivo."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica nueva usa Naruto para derrotar a Kakuzu?",o:["Rasen Shuriken", "Rasengan normal", "Modo Sabio", "Bijuudama"],a:0,exp:"Naruto usa por primera vez el F\u016bton: Rasen Shuriken contra Kakuzu.",extra:"La t\u00e9cnica combina el Rasengan con naturaleza de viento y causa da\u00f1o microsc\u00f3pico al sistema de chakra."},
  {t:"m",q:"\u00bfQu\u00e9 maestro de Naruto muere investigando a Pain?",o:["Jiraiya", "Kakashi", "Iruka", "Yamato"],a:0,exp:"Jiraiya muere en Amegakure mientras investiga el secreto de Pain.",extra:"Su muerte es uno de los golpes emocionales m\u00e1s grandes para Naruto y lo empuja a madurar como ninja y persona."},
  {t:"m",q:"\u00bfCu\u00e1l era el nombre real de Pain?",o:["Nagato", "Yahiko", "Obito", "Madara"],a:0,exp:"El verdadero usuario detr\u00e1s de Pain era Nagato.",extra:"Nagato controlaba los Seis Caminos de Pain usando cuerpos, incluido el de su amigo Yahiko."},
  {t:"m",q:"\u00bfQui\u00e9nes fueron los tres hu\u00e9rfanos de Amegakure entrenados por Jiraiya?",o:["Nagato, Yahiko y Konan", "Naruto, Sasuke y Sakura", "Itachi, Kisame y Deidara", "Obito, Rin y Kakashi"],a:0,exp:"Jiraiya entren\u00f3 a Nagato, Yahiko y Konan durante la guerra.",extra:"Ese v\u00ednculo hace m\u00e1s tr\u00e1gico el enfrentamiento posterior entre Naruto y Pain, porque ambos son disc\u00edpulos de Jiraiya con respuestas opuestas al dolor."},
  {t:"m",q:"\u00bfQu\u00e9 d\u014djutsu posee Nagato?",o:["Rinnegan", "Sharingan", "Byakugan", "Tenseigan"],a:0,exp:"Nagato posee el Rinnegan.",extra:"M\u00e1s tarde se revela que esos ojos originalmente pertenec\u00edan a Madara, quien los implant\u00f3 en Nagato como parte de un plan mayor."},
  {t:"m",q:"\u00bfQu\u00e9 aldea destruye Pain con Shinra Tensei?",o:["Konoha", "Suna", "Kiri", "Iwa"],a:0,exp:"Pain destruye gran parte de Konoha usando Shinra Tensei.",extra:"La llegada de Naruto en Modo Sabio despu\u00e9s de la destrucci\u00f3n es uno de los momentos m\u00e1s heroicos de la serie."},
  {t:"m",q:"\u00bfQu\u00e9 modo aprende Naruto en el Monte Myoboku?",o:["Modo Sabio", "Modo Kurama", "Modo Rikudou", "Modo Anbu"],a:0,exp:"Naruto aprende el Modo Sabio en el Monte Myoboku.",extra:"El Modo Sabio usa energ\u00eda natural para potenciar fuerza, percepci\u00f3n y ninjutsu. Requiere equilibrio perfecto para evitar convertirse en sapo."},
  {t:"m",q:"\u00bfQu\u00e9 animales invoca Naruto mediante contrato?",o:["Sapos", "Serpientes", "Perros", "Babosas"],a:0,exp:"Naruto tiene contrato de invocaci\u00f3n con los sapos del Monte Myoboku.",extra:"Gamabunta, Gamakichi y Fukasaku son algunas de las invocaciones m\u00e1s importantes relacionadas con Naruto y Jiraiya."},
  {t:"m",q:"\u00bfQu\u00e9 animal invoca Tsunade?",o:["Katsuyu", "Manda", "Gamabunta", "Pakkun"],a:0,exp:"Tsunade invoca a Katsuyu, una babosa gigante.",extra:"Katsuyu puede dividirse, curar y transmitir chakra, lo que la hace vital en batallas masivas y situaciones m\u00e9dicas."},
  {t:"m",q:"\u00bfQu\u00e9 animal invocaba Orochimaru frecuentemente?",o:["Serpientes", "Sapos", "Perros", "Halcones"],a:0,exp:"Orochimaru usa invocaciones de serpientes.",extra:"Manda era una de sus invocaciones m\u00e1s poderosas, aunque tambi\u00e9n extremadamente arrogante y dif\u00edcil de controlar."},
  {t:"m",q:"\u00bfQu\u00e9 invocaci\u00f3n canina usa Kakashi?",o:["Pakkun", "Akamaru", "Katsuyu", "Kuromaru"],a:0,exp:"Pakkun es uno de los perros ninja de Kakashi.",extra:"Kakashi usa perros ninja para rastrear enemigos y apoyar misiones, reflejando su estilo t\u00e1ctico."},
  {t:"m",q:"\u00bfQui\u00e9n fue el mejor amigo de Kakashi en su juventud?",o:["Obito Uchiha", "Itachi Uchiha", "Asuma Sarutobi", "Might Guy"],a:0,exp:"Obito Uchiha fue compa\u00f1ero de Kakashi en el Equipo Minato.",extra:"La aparente muerte de Obito y su regalo del Sharingan marcan la vida de Kakashi para siempre."},
  {t:"m",q:"\u00bfQui\u00e9n le dio a Kakashi su Sharingan?",o:["Obito", "Itachi", "Madara", "Shisui"],a:0,exp:"Obito le dio a Kakashi su Sharingan como regalo antes de supuestamente morir.",extra:"Ese ojo se convierte en s\u00edmbolo de la promesa de Kakashi de proteger a sus compa\u00f1eros."},
  {t:"m",q:"\u00bfQu\u00e9 compa\u00f1era de Kakashi y Obito muere tr\u00e1gicamente?",o:["Rin Nohara", "Kurenai Yuhi", "Anko Mitarashi", "Shizune"],a:0,exp:"Rin Nohara muere atravesada por el Chidori de Kakashi en circunstancias tr\u00e1gicas.",extra:"Su muerte es manipulada por Madara para quebrar emocionalmente a Obito y empujarlo hacia el Plan Ojo de Luna."},
  {t:"m",q:"\u00bfQu\u00e9 identidad usa Obito durante gran parte de Akatsuki?",o:["Tobi", "Pain", "Zetsu", "Kisame"],a:0,exp:"Obito usa la identidad de Tobi dentro de Akatsuki.",extra:"Al principio parece un personaje c\u00f3mico e incompetente, pero luego se revela como una de las mayores amenazas de la historia."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica espacial usa el Mangekyo Sharingan de Obito?",o:["Kamui", "Amaterasu", "Tsukuyomi", "Kotoamatsukami"],a:0,exp:"Obito usa Kamui para transportar partes de su cuerpo u objetos a otra dimensi\u00f3n.",extra:"Kamui lo vuelve casi intocable, ya que puede hacer que ataques atraviesen su cuerpo enviando la zona afectada a otra dimensi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica de Itachi genera llamas negras?",o:["Amaterasu", "Tsukuyomi", "Susanoo", "Izanagi"],a:0,exp:"Amaterasu produce llamas negras que arden hasta consumir su objetivo.",extra:"Es una de las t\u00e9cnicas m\u00e1s temidas del Mangekyo Sharingan y luego Sasuke tambi\u00e9n la utiliza."},
  {t:"m",q:"\u00bfQu\u00e9 genjutsu poderoso usa Itachi con su Mangekyo?",o:["Tsukuyomi", "Izanami", "Kotoamatsukami", "Mugen Tsukuyomi"],a:0,exp:"Itachi usa Tsukuyomi, un genjutsu que altera la percepci\u00f3n del tiempo y causa tortura mental.",extra:"La t\u00e9cnica demuestra que Itachi no solo era fuerte f\u00edsicamente, sino uno de los usuarios de genjutsu m\u00e1s peligrosos de la serie."},
  {t:"m",q:"\u00bfQu\u00e9 avatar defensivo gigante pueden usar algunos usuarios del Mangekyo Sharingan?",o:["Susanoo", "Kurama", "Izanagi", "Kirin"],a:0,exp:"Susanoo es una manifestaci\u00f3n gigante de chakra usada por ciertos usuarios del Mangekyo.",extra:"Itachi, Sasuke, Madara y Kakashi llegan a usar versiones de Susanoo con armas y habilidades diferentes."},
  {t:"m",q:"\u00bfQu\u00e9 arma legendaria ten\u00eda el Susanoo de Itachi?",o:["Espada de Totsuka", "Samehada", "Kubikiribocho", "Espada Kusanagi"],a:0,exp:"El Susanoo de Itachi porta la Espada de Totsuka.",extra:"La Espada de Totsuka puede sellar a quien atraviesa, convirti\u00e9ndola en un arma espiritual extremadamente poderosa."},
  {t:"m",q:"\u00bfQu\u00e9 espejo defensivo ten\u00eda el Susanoo de Itachi?",o:["Espejo de Yata", "Escudo Uzumaki", "Barrera Hyuga", "Espejo Senju"],a:0,exp:"El Susanoo de Itachi usa el Espejo de Yata como defensa.",extra:"Combinado con la Espada de Totsuka, el Susanoo de Itachi es presentado como una defensa y ataque casi perfectos."},
  {t:"m",q:"\u00bfQu\u00e9 amigo de Itachi pose\u00eda Kotoamatsukami?",o:["Shisui Uchiha", "Madara Uchiha", "Fugaku Uchiha", "Obito Uchiha"],a:0,exp:"Shisui Uchiha pose\u00eda Kotoamatsukami, un genjutsu de manipulaci\u00f3n sutil.",extra:"Su ojo fue codiciado por Danzo, y su muerte influy\u00f3 profundamente en Itachi antes de la masacre Uchiha."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00edder de Ra\u00edz rob\u00f3 ojos Sharingan y manipul\u00f3 la pol\u00edtica de Konoha?",o:["Danzo Shimura", "Homura Mitokado", "Koharu Utatane", "Ibiki Morino"],a:0,exp:"Danzo Shimura lider\u00f3 Ra\u00edz y actu\u00f3 desde las sombras de Konoha.",extra:"Danzo representa el lado oscuro de la aldea: decisiones crueles justificadas como protecci\u00f3n del sistema."},
  {t:"m",q:"\u00bfQui\u00e9n mata a Danzo?",o:["Sasuke", "Naruto", "Itachi", "Kakashi"],a:0,exp:"Sasuke mata a Danzo tras la Cumbre de los Kage.",extra:"La pelea revela el uso de m\u00faltiples Sharingan por parte de Danzo y su acceso a Izanagi."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica permite alterar la realidad a cambio de perder la luz de un Sharingan?",o:["Izanagi", "Amaterasu", "Tsukuyomi", "Kamui"],a:0,exp:"Izanagi permite convertir da\u00f1o o muerte en ilusi\u00f3n durante un breve tiempo.",extra:"Es una t\u00e9cnica prohibida porque sacrifica la visi\u00f3n del ojo usado. Danzo la usa repetidamente gracias a los Sharingan implantados."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Itachi para detener a Kabuto?",o:["Izanami", "Izanagi", "Kotoamatsukami", "Tsukuyomi Infinito"],a:0,exp:"Itachi usa Izanami para atrapar a Kabuto en un ciclo hasta que acepte su verdadero yo.",extra:"Izanami fue creada como contrapeso a Izanagi, castigando a quienes intentan escapar de la realidad mediante ilusiones."},
  {t:"m",q:"\u00bfQu\u00e9 espada viviente usa Kisame Hoshigaki?",o:["Samehada", "Kusanagi", "Shibuki", "Nuibari"],a:0,exp:"Kisame usa Samehada, una espada que devora chakra.",extra:"Samehada est\u00e1 viva y puede elegir a su usuario. Su afinidad con Kisame lo convierte en un monstruo de chakra."},
  {t:"m",q:"\u00bfDe qu\u00e9 aldea era Kisame?",o:["Aldea de la Niebla", "Aldea de la Arena", "Aldea de la Roca", "Aldea de la Nube"],a:0,exp:"Kisame era de Kirigakure, la Aldea Oculta de la Niebla.",extra:"Fue uno de los Siete Espadachines de la Niebla, un grupo legendario de ninjas armados con espadas especiales."},
  {t:"m",q:"\u00bfQu\u00e9 grupo de espadachines legendarios pertenece a Kirigakure?",o:["Siete Espadachines de la Niebla", "Doce Guardianes Ninja", "Ra\u00edz", "Sannin"],a:0,exp:"Los Siete Espadachines de la Niebla son ninjas de \u00e9lite de Kirigakure.",extra:"Zabuza y Kisame fueron miembros de este grupo, asociado a armas \u00fanicas y reputaci\u00f3n brutal."},
  {t:"m",q:"\u00bfQu\u00e9 espada usaba Zabuza?",o:["Kubikiribocho", "Samehada", "Hiramekarei", "Kiba"],a:0,exp:"Zabuza usaba Kubikiribocho, la Espada Decapitadora.",extra:"La espada puede regenerarse usando el hierro de la sangre de sus v\u00edctimas, encajando con la brutalidad de su nombre."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki es una usuaria de papel?",o:["Konan", "Karin", "Tayuya", "Pakura"],a:0,exp:"Konan usa t\u00e9cnicas basadas en papel.",extra:"Su pelea contra Obito demuestra preparaci\u00f3n extrema y lealtad absoluta a Nagato y Yahiko."},
  {t:"m",q:"\u00bfQu\u00e9 plan busca encerrar al mundo en un sue\u00f1o eterno?",o:["Plan Ojo de Luna", "Operaci\u00f3n Konoha Crush", "Proyecto Tsuki", "Plan Ra\u00edz"],a:0,exp:"El Plan Ojo de Luna busca atrapar al mundo en el Tsukuyomi Infinito.",extra:"Obito y Madara lo presentan como una soluci\u00f3n al sufrimiento, pero en realidad elimina libertad y realidad."},
  {t:"m",q:"\u00bfQu\u00e9 \u00e1rbol divino est\u00e1 ligado al origen del chakra?",o:["\u00c1rbol Dios", "\u00c1rbol Senju", "\u00c1rbol Uzumaki", "\u00c1rbol de Konoha"],a:0,exp:"El \u00c1rbol Dios est\u00e1 ligado al origen del chakra y al Diez Colas.",extra:"Kaguya consume el fruto del \u00c1rbol Dios, introduciendo el chakra en la historia humana."},
  {t:"m",q:"\u00bfQui\u00e9n fue la primera persona en usar chakra seg\u00fan el mito de Naruto?",o:["Kaguya Otsutsuki", "Hagoromo", "Hamura", "Madara"],a:0,exp:"Kaguya Otsutsuki fue la primera en obtener chakra al consumir el fruto del \u00c1rbol Dios.",extra:"Su llegada cambia el mundo ninja desde una escala hist\u00f3rica a una dimensi\u00f3n casi mitol\u00f3gica y alien\u00edgena."},
  {t:"m",q:"\u00bfQui\u00e9n es conocido como el Sabio de los Seis Caminos?",o:["Hagoromo Otsutsuki", "Hamura Otsutsuki", "Hashirama Senju", "Madara Uchiha"],a:0,exp:"Hagoromo Otsutsuki es el Sabio de los Seis Caminos.",extra:"Hagoromo distribuy\u00f3 el chakra y fund\u00f3 el ninshu, que m\u00e1s tarde se deform\u00f3 en ninjutsu usado para la guerra."},
  {t:"m",q:"\u00bfQui\u00e9nes son los hijos de Hagoromo que originan la rivalidad heredada?",o:["Indra y Asura", "Madara y Hashirama", "Naruto y Sasuke", "Hamura y Kaguya"],a:0,exp:"Indra y Asura son los hijos de Hagoromo.",extra:"Sus conflictos espirituales se reencarnan a lo largo de generaciones, incluyendo Madara y Hashirama, luego Sasuke y Naruto."},
  {t:"m",q:"\u00bfQui\u00e9n es la reencarnaci\u00f3n de Asura en la era principal?",o:["Naruto", "Sasuke", "Kakashi", "Neji"],a:0,exp:"Naruto es la reencarnaci\u00f3n de Asura.",extra:"Asura representa cooperaci\u00f3n, v\u00ednculos y crecimiento a trav\u00e9s de otros, rasgos centrales del camino de Naruto."},
  {t:"m",q:"\u00bfQui\u00e9n es la reencarnaci\u00f3n de Indra en la era principal?",o:["Sasuke", "Naruto", "Itachi", "Madara"],a:0,exp:"Sasuke es la reencarnaci\u00f3n de Indra.",extra:"Indra representa talento individual, orgullo y aislamiento, elementos que definen gran parte del conflicto interno de Sasuke."},
  {t:"m",q:"\u00bfQui\u00e9n fue rival hist\u00f3rico de Hashirama?",o:["Madara Uchiha", "Tobirama Senju", "Hiruzen Sarutobi", "Izuna Uchiha"],a:0,exp:"Madara Uchiha fue el gran rival de Hashirama Senju.",extra:"Ambos so\u00f1aban con paz, pero sus m\u00e9todos y traumas los llevaron por caminos opuestos."},
  {t:"m",q:"\u00bfQu\u00e9 aldea fundaron Hashirama y Madara?",o:["Konoha", "Suna", "Kiri", "Kumo"],a:0,exp:"Hashirama y Madara fundaron Konohagakure.",extra:"La fundaci\u00f3n de Konoha buscaba terminar con la era de clanes mercenarios, aunque sus conflictos internos continuaron de otras formas."},
  {t:"m",q:"\u00bfQu\u00e9 batalla hist\u00f3rica ocurri\u00f3 en el Valle del Fin?",o:["Hashirama contra Madara", "Jiraiya contra Orochimaru", "Minato contra Obito", "Itachi contra Sasuke"],a:0,exp:"Hashirama y Madara lucharon en el Valle del Fin.",extra:"Las estatuas gigantes de ambos fundadores simbolizan la rivalidad que Naruto y Sasuke repetir\u00e1n generaciones despu\u00e9s."},
  {t:"m",q:"\u00bfQu\u00e9 batalla final de la primera parte ocurre en el Valle del Fin?",o:["Naruto contra Sasuke", "Naruto contra Gaara", "Sasuke contra Itachi", "Kakashi contra Zabuza"],a:0,exp:"Naruto y Sasuke pelean en el Valle del Fin al final de la primera parte.",extra:"La pelea marca la ruptura del Equipo 7 y el inicio del camino oscuro de Sasuke con Orochimaru."},
  {t:"m",q:"\u00bfQu\u00e9 equipo se forma para recuperar a Sasuke cuando abandona Konoha?",o:["Equipo de recuperaci\u00f3n de Sasuke", "Equipo ANBU", "Equipo Akatsuki", "Equipo Ra\u00edz"],a:0,exp:"Shikamaru lidera el equipo de recuperaci\u00f3n de Sasuke.",extra:"El equipo incluye a Naruto, Neji, Choji, Kiba y Shikamaru, con ayuda posterior de los ninjas de la Arena."},
  {t:"m",q:"\u00bfQui\u00e9n pelea contra Kimimaro durante la recuperaci\u00f3n de Sasuke?",o:["Rock Lee y Gaara", "Naruto y Sakura", "Kakashi y Guy", "Neji y Kiba"],a:0,exp:"Rock Lee enfrenta a Kimimaro y luego Gaara interviene.",extra:"Kimimaro es el \u00faltimo miembro del clan Kaguya y uno de los subordinados m\u00e1s fuertes de Orochimaru."},
  {t:"m",q:"\u00bfQu\u00e9 kekkei genkai usa Kimimaro?",o:["Huesos", "Hielo", "Madera", "Lava"],a:0,exp:"Kimimaro usa Shikotsumyaku, manipulaci\u00f3n de huesos.",extra:"Puede extraer y modificar sus propios huesos como armas, una habilidad visualmente brutal y muy rara."},
  {t:"m",q:"\u00bfQu\u00e9 miembro del equipo de recuperaci\u00f3n casi muere contra Kidomaru?",o:["Neji", "Choji", "Kiba", "Shikamaru"],a:0,exp:"Neji derrota a Kidomaru en una pelea muy dif\u00edcil y queda gravemente herido.",extra:"La pelea demuestra el talento de Neji y su evoluci\u00f3n tras superar su visi\u00f3n fatalista del destino."},
  {t:"m",q:"\u00bfQu\u00e9 miembro del equipo de recuperaci\u00f3n usa p\u00edldoras especiales contra Jirobo?",o:["Choji", "Kiba", "Shikamaru", "Naruto"],a:0,exp:"Choji usa las p\u00edldoras del clan Akimichi para derrotar a Jirobo.",extra:"La \u00faltima p\u00edldora le da alas de mariposa de chakra y casi le cuesta la vida, mostrando su crecimiento y valent\u00eda."},
  {t:"m",q:"\u00bfQui\u00e9n es el l\u00edder original idealista de Akatsuki?",o:["Yahiko", "Nagato", "Obito", "Madara"],a:0,exp:"Yahiko fund\u00f3 Akatsuki con un ideal de paz en Amegakure.",extra:"Tras su muerte, Nagato transforma Akatsuki en algo mucho m\u00e1s oscuro bajo la influencia de Obito."},
  {t:"m",q:"\u00bfQu\u00e9 aldea era gobernada por Hanzo de la Salamandra?",o:["Amegakure", "Konoha", "Suna", "Kiri"],a:0,exp:"Hanzo gobernaba Amegakure, la Aldea Oculta de la Lluvia.",extra:"Hanzo fue tan poderoso que nombr\u00f3 Sannin a Jiraiya, Tsunade y Orochimaru tras sobrevivir a una batalla contra \u00e9l."},
  {t:"m",q:"\u00bfQui\u00e9n mat\u00f3 a Hanzo m\u00e1s adelante?",o:["Pain", "Naruto", "Jiraiya", "Danzo"],a:0,exp:"Pain mat\u00f3 a Hanzo y tom\u00f3 control de Amegakure.",extra:"Ese acto marca la transformaci\u00f3n completa de Nagato en un l\u00edder basado en miedo y dolor."},
  {t:"m",q:"\u00bfQu\u00e9 Kage lidera la Aldea de la Arena?",o:["Kazekage", "Hokage", "Mizukage", "Raikage"],a:0,exp:"El Kazekage es el l\u00edder de Sunagakure.",extra:"Gaara se convierte en Kazekage y cambia la percepci\u00f3n de su aldea sobre \u00e9l."},
  {t:"m",q:"\u00bfQu\u00e9 Kage lidera la Aldea de la Nube?",o:["Raikage", "Tsuchikage", "Mizukage", "Kazekage"],a:0,exp:"El Raikage lidera Kumogakure, la Aldea Oculta de la Nube.",extra:"El Cuarto Raikage, A, es conocido por su velocidad, fuerza f\u00edsica y car\u00e1cter explosivo."},
  {t:"m",q:"\u00bfQu\u00e9 Kage lidera la Aldea de la Roca?",o:["Tsuchikage", "Mizukage", "Hokage", "Kazekage"],a:0,exp:"El Tsuchikage lidera Iwagakure, la Aldea Oculta de la Roca.",extra:"Onoki, el Tercer Tsuchikage, posee el Elemento Polvo, una t\u00e9cnica extremadamente destructiva."},
  {t:"m",q:"\u00bfQu\u00e9 Kage lidera la Aldea de la Niebla?",o:["Mizukage", "Raikage", "Tsuchikage", "Kazekage"],a:0,exp:"El Mizukage lidera Kirigakure, la Aldea Oculta de la Niebla.",extra:"Mei Terumi es la Quinta Mizukage y ayuda a reformar la imagen sangrienta de su aldea."},
  {t:"m",q:"\u00bfQu\u00e9 jinchuriki del Ocho Colas se vuelve aliado de Naruto?",o:["Killer Bee", "Yugito", "Yagura", "Roshi"],a:0,exp:"Killer Bee es jinchuriki de Gyuki, el Ocho Colas.",extra:"Bee ense\u00f1a a Naruto a cooperar con su bestia con cola y controlar mejor su poder."},
  {t:"m",q:"\u00bfQu\u00e9 estilo musical caracteriza a Killer Bee?",o:["Rap", "\u00d3pera", "Baladas", "Cantos rituales"],a:0,exp:"Killer Bee suele hablar y componer versos de rap.",extra:"Su personalidad extravagante contrasta con su enorme habilidad ninja y dominio como jinchuriki perfecto."},
  {t:"m",q:"\u00bfQui\u00e9n es el hermano adoptivo del Cuarto Raikage?",o:["Killer Bee", "Darui", "Omoi", "C"],a:0,exp:"Killer Bee es hermano adoptivo del Cuarto Raikage.",extra:"Su v\u00ednculo fraternal es intenso: el Raikage es duro con Bee, pero lo protege profundamente."},
  {t:"m",q:"\u00bfQu\u00e9 guerra ocupa gran parte del final de Naruto Shippuden?",o:["Cuarta Gran Guerra Ninja", "Tercera Guerra Ninja", "Guerra de Konoha", "Guerra de los Kage"],a:0,exp:"La Cuarta Gran Guerra Ninja enfrenta a la Alianza Shinobi contra Obito, Madara y sus fuerzas.",extra:"La guerra re\u00fane a las cinco grandes aldeas contra una amenaza com\u00fan, rompiendo siglos de rivalidad."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica revive a ninjas muertos durante la guerra?",o:["Edo Tensei", "Izanagi", "Kuchiyose", "Byakugo"],a:0,exp:"El Edo Tensei revive muertos como cuerpos inmortales controlables.",extra:"Fue creada por Tobirama, perfeccionada por Orochimaru y usada masivamente por Kabuto durante la guerra."},
  {t:"m",q:"\u00bfQui\u00e9n usa masivamente Edo Tensei en la Cuarta Guerra Ninja?",o:["Kabuto", "Orochimaru", "Madara", "Danzo"],a:0,exp:"Kabuto usa Edo Tensei para revivir a muchos shinobi poderosos.",extra:"Su dominio de la t\u00e9cnica lo convierte en una pieza clave del bando enemigo antes de ser detenido por Itachi y Sasuke."},
  {t:"m",q:"\u00bfQu\u00e9 ninja m\u00e9dico se obsesiona con Orochimaru y luego se transforma a s\u00ed mismo?",o:["Kabuto Yakushi", "Sai", "Yamato", "Suigetsu"],a:0,exp:"Kabuto Yakushi pasa de esp\u00eda m\u00e9dico a seguidor obsesivo de Orochimaru.",extra:"Despu\u00e9s de absorber c\u00e9lulas y t\u00e9cnicas de varios ninjas, intenta definirse a s\u00ed mismo mediante poder ajeno."},
  {t:"m",q:"\u00bfQu\u00e9 modo aprende Kabuto en la cueva Ryuchi?",o:["Modo Sabio de Serpiente", "Modo Kurama", "Modo Rikudou", "Modo Byakugo"],a:0,exp:"Kabuto aprende el Modo Sabio de Serpiente.",extra:"Este poder lo vuelve lo bastante peligroso como para enfrentar a Itachi y Sasuke simult\u00e1neamente."},
  {t:"m",q:"\u00bfQui\u00e9n rompe el control del Edo Tensei sobre s\u00ed mismo?",o:["Itachi", "Deidara", "Sasori", "Nagato"],a:0,exp:"Itachi logra liberarse del control de Kabuto gracias al Kotoamatsukami preparado en el cuervo de Naruto.",extra:"Liberado, Itachi ayuda a detener el Edo Tensei y tiene una \u00faltima conversaci\u00f3n crucial con Sasuke."},
  {t:"m",q:"\u00bfQui\u00e9n se revela como el verdadero Madara reanimado durante la guerra?",o:["Madara Uchiha", "Obito Uchiha", "Izuna Uchiha", "Shisui Uchiha"],a:0,exp:"El verdadero Madara aparece reanimado por Edo Tensei.",extra:"Su aparici\u00f3n demuestra que el hombre enmascarado no era Madara, sino Obito usando su nombre."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Madara para invocar meteoritos?",o:["Tengai Shinsei", "Chibaku Tensei", "Shinra Tensei", "Kamui"],a:0,exp:"Madara usa Tengai Shinsei para hacer caer meteoritos gigantes.",extra:"La escena deja clara la diferencia de escala entre Madara y la mayor\u00eda de shinobi comunes."},
  {t:"m",q:"\u00bfQu\u00e9 poder ocular obtiene Sasuke de Hagoromo?",o:["Rinnegan especial", "Byakugan", "Tenseigan", "Jogan"],a:0,exp:"Sasuke obtiene un Rinnegan especial en un ojo gracias al poder de Hagoromo.",extra:"Ese Rinnegan le permite t\u00e9cnicas espacio-temporales como Amenotejikara."},
  {t:"m",q:"\u00bfQu\u00e9 poder recibe Naruto de Hagoromo?",o:["Poder del Sabio de los Seis Caminos", "Sharingan", "Byakugan", "Sello Maldito"],a:0,exp:"Naruto recibe poder del Sabio de los Seis Caminos.",extra:"Esto amplifica sus habilidades, le permite sentir emociones oscuras y usar chakra de las bestias con cola."},
  {t:"m",q:"\u00bfQui\u00e9n es la madre de Hagoromo y Hamura?",o:["Kaguya Otsutsuki", "Mito Uzumaki", "Rin Nohara", "Konan"],a:0,exp:"Kaguya Otsutsuki es madre de Hagoromo y Hamura.",extra:"Kaguya se convierte en la amenaza final original de la serie al ser revivida mediante Madara."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica atrapa al mundo en un genjutsu proyectado desde la luna?",o:["Tsukuyomi Infinito", "Tsukuyomi", "Kotoamatsukami", "Izanami"],a:0,exp:"El Tsukuyomi Infinito atrapa a la humanidad en sue\u00f1os ilusorios.",extra:"La t\u00e9cnica promete paz, pero en realidad convierte a las personas en prisioneras y alimento del \u00c1rbol Dios."},
  {t:"m",q:"\u00bfQui\u00e9n traiciona a Madara para revivir a Kaguya?",o:["Zetsu Negro", "Obito", "Kabuto", "Orochimaru"],a:0,exp:"Zetsu Negro traiciona a Madara y lo usa para traer de vuelta a Kaguya.",extra:"Zetsu Negro revela haber manipulado la historia durante siglos para cumplir la voluntad de Kaguya."},
  {t:"m",q:"\u00bfQu\u00e9 personaje queda atrapado inicialmente en una dimensi\u00f3n de lava de Kaguya?",o:["Equipo 7", "Solo Naruto", "Solo Sasuke", "Los Cinco Kage"],a:0,exp:"Kaguya transporta al Equipo 7 a varias dimensiones, incluyendo una de lava.",extra:"Sus dimensiones muestran un tipo de poder muy diferente al ninjutsu convencional, m\u00e1s cercano al origen Otsutsuki del chakra."},
  {t:"m",q:"\u00bfQui\u00e9n ayuda a sellar a Kaguya junto a Naruto y Sasuke?",o:["Sakura y Kakashi", "Gaara y Lee", "Tsunade y Jiraiya", "Itachi y Shisui"],a:0,exp:"Sakura y Kakashi son clave para que Naruto y Sasuke logren sellar a Kaguya.",extra:"La escena funciona como cierre simb\u00f3lico del Equipo 7 original, con todos participando en la victoria."},
  {t:"m",q:"\u00bfD\u00f3nde ocurre la batalla final entre Naruto y Sasuke?",o:["Valle del Fin", "Monte Myoboku", "Konoha", "Amegakure"],a:0,exp:"Naruto y Sasuke tienen su batalla final en el Valle del Fin.",extra:"El lugar refleja la repetici\u00f3n del conflicto entre Hashirama y Madara, pero Naruto busca romper ese ciclo."},
  {t:"m",q:"\u00bfQu\u00e9 pierden Naruto y Sasuke al final de su pelea final?",o:["Un brazo cada uno", "Sus ojos", "Sus bestias con cola", "Sus recuerdos"],a:0,exp:"Naruto y Sasuke pierden un brazo cada uno tras el choque final.",extra:"La imagen de ambos heridos y reconciliados cierra su rivalidad principal de forma f\u00edsica y emocional."},
  {t:"m",q:"\u00bfQui\u00e9n se convierte en Sexto Hokage?",o:["Kakashi Hatake", "Naruto Uzumaki", "Tsunade", "Shikamaru"],a:0,exp:"Kakashi se convierte en el Sexto Hokage despu\u00e9s de la guerra.",extra:"Su mandato sirve como puente entre la era de guerra y la paz posterior antes de que Naruto asuma el cargo."},
  {t:"m",q:"\u00bfQui\u00e9n se convierte en S\u00e9ptimo Hokage?",o:["Naruto Uzumaki", "Sasuke Uchiha", "Konohamaru", "Shikamaru"],a:0,exp:"Naruto finalmente se convierte en el S\u00e9ptimo Hokage.",extra:"El logro completa su sue\u00f1o inicial, pero con un significado m\u00e1s profundo: ya no busca ser reconocido, sino cuidar a todos los que lo reconocen."},
  {t:"m",q:"\u00bfCon qui\u00e9n se casa Naruto?",o:["Hinata Hyuga", "Sakura Haruno", "Ino Yamanaka", "Tenten"],a:0,exp:"Naruto se casa con Hinata Hyuga.",extra:"Hinata admir\u00f3 a Naruto desde ni\u00f1a porque ve\u00eda en \u00e9l la fuerza de no rendirse. Su relaci\u00f3n se desarrolla con m\u00e1s claridad en The Last."},
  {t:"m",q:"\u00bfCon qui\u00e9n se casa Sasuke?",o:["Sakura Haruno", "Karin", "Ino Yamanaka", "Temari"],a:0,exp:"Sasuke se casa con Sakura Haruno.",extra:"Su relaci\u00f3n es compleja por el pasado oscuro de Sasuke, pero en la era posterior tienen una hija llamada Sarada."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el hijo de Naruto y Hinata?",o:["Boruto", "Menma", "Kawaki", "Konohamaru"],a:0,exp:"El hijo de Naruto y Hinata se llama Boruto.",extra:"Boruto protagoniza la secuela y vive a la sombra del legado enorme de su padre como Hokage."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la hija de Naruto y Hinata?",o:["Himawari", "Sarada", "Sumire", "Hanabi"],a:0,exp:"La hija menor de Naruto y Hinata se llama Himawari.",extra:"Himawari hereda rasgos Hyuga y Uzumaki. En una escena c\u00f3mica, llega a noquear a Naruto activando el Byakugan."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la hija de Sasuke y Sakura?",o:["Sarada", "Himawari", "Sumire", "Chocho"],a:0,exp:"La hija de Sasuke y Sakura se llama Sarada Uchiha.",extra:"Sarada quiere convertirse en Hokage, una inversi\u00f3n interesante del camino de su padre y una continuaci\u00f3n del legado Uchiha."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se vuelve pareja de Temari?",o:["Shikamaru", "Naruto", "Kiba", "Choji"],a:0,exp:"Shikamaru y Temari terminan formando pareja.",extra:"Su din\u00e1mica empieza con rivalidad en los Ex\u00e1menes Chunin y evoluciona hacia una relaci\u00f3n basada en respeto e inteligencia."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se casa con Karui de la Aldea de la Nube?",o:["Choji", "Shino", "Kiba", "Lee"],a:0,exp:"Choji se casa con Karui.",extra:"Su hija, Chocho, hereda la fuerza del clan Akimichi y una personalidad muy segura de s\u00ed misma."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre de Konohamaru?",o:["No se centra en la historia principal", "Asuma Sarutobi", "Hiruzen Sarutobi", "Ebisu"],a:0,exp:"El padre de Konohamaru no es un foco importante de la historia principal.",extra:"Konohamaru es nieto del Tercer Hokage y sobrino de Asuma. Su v\u00ednculo m\u00e1s importante en pantalla es su admiraci\u00f3n por Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica aprende Konohamaru de Naruto?",o:["Rasengan", "Chidori", "Amaterasu", "Byakugan"],a:0,exp:"Konohamaru aprende el Rasengan de Naruto.",extra:"Durante el ataque de Pain, Konohamaru usa el Rasengan para derrotar a un cuerpo de Pain, demostrando su crecimiento."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica pervertida inventa Naruto como recurso c\u00f3mico?",o:["Sexy no Jutsu", "Chidori no Jutsu", "Sombra Sensual", "Harem Rasengan"],a:0,exp:"Naruto usa el Sexy no Jutsu como t\u00e9cnica de transformaci\u00f3n c\u00f3mica.",extra:"Aunque es un gag, Naruto la usa de forma sorprendentemente efectiva incluso contra enemigos poderosos distra\u00eddos por lo absurdo."},
  {t:"m",q:"\u00bfQu\u00e9 variante m\u00faltiple combina clones con el Sexy no Jutsu?",o:["Harem no Jutsu", "Kage Harem", "Sexy Bunshin", "Naruto Girls Jutsu"],a:0,exp:"El Harem no Jutsu combina clones de sombra con transformaciones seductoras.",extra:"Es una de las t\u00e9cnicas c\u00f3micas m\u00e1s famosas de Naruto y refleja su creatividad irreverente."},
  {t:"m",q:"\u00bfQu\u00e9 ninja usa arena como defensa autom\u00e1tica?",o:["Gaara", "Kankuro", "Temari", "Sasori"],a:0,exp:"Gaara usa arena para atacar y defenderse autom\u00e1ticamente.",extra:"La arena lo proteg\u00eda incluso sin intenci\u00f3n consciente, por influencia de su madre y del Shukaku sellado en \u00e9l."},
  {t:"m",q:"\u00bfQu\u00e9 frase resume la regla de Kakashi sobre compa\u00f1eros?",o:["Quienes abandonan a sus amigos son peor que escoria", "El poder lo es todo", "La venganza trae paz", "Un ninja nunca llora"],a:0,exp:"Kakashi ense\u00f1a que quienes abandonan a sus compa\u00f1eros son peor que escoria.",extra:"La frase viene de Obito y se convierte en una br\u00fajula moral para Kakashi y luego para el Equipo 7."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki tiene dos mitades, blanca y negra?",o:["Zetsu", "Kakuzu", "Pain", "Sasori"],a:0,exp:"Zetsu tiene una mitad blanca y una negra.",extra:"Zetsu Negro cumple un papel much\u00edsimo m\u00e1s importante de lo que aparenta, como voluntad de Kaguya y manipulador hist\u00f3rico."},
  {t:"m",q:"\u00bfQu\u00e9 biju tiene diez colas?",o:["Juubi", "Kurama", "Gyuki", "Shukaku"],a:0,exp:"El Juubi, o Diez Colas, es la bestia con cola original.",extra:"Las nueve bestias con cola provienen de la divisi\u00f3n del chakra del Diez Colas realizada por Hagoromo."},
  {t:"m",q:"\u00bfQui\u00e9n dividi\u00f3 el chakra del Diez Colas en nueve bestias?",o:["Hagoromo", "Hashirama", "Madara", "Kaguya"],a:0,exp:"Hagoromo dividi\u00f3 el chakra del Diez Colas en las nueve bestias con cola.",extra:"Tambi\u00e9n les dio nombres, reconoci\u00e9ndolas como seres con identidad propia y no solo como armas."},
  {t:"m",q:"\u00bfQu\u00e9 nombre recibe la bestia de ocho colas?",o:["Gyuki", "Kurama", "Shukaku", "Son Goku"],a:0,exp:"La bestia de ocho colas se llama Gyuki.",extra:"Gyuki tiene forma de toro-pulpo y mantiene una relaci\u00f3n cooperativa con Killer Bee."},
  {t:"m",q:"\u00bfQu\u00e9 biju tiene forma de mapache de arena?",o:["Shukaku", "Matatabi", "Isobu", "Chomei"],a:0,exp:"Shukaku, el Una Cola, tiene forma de tanuki o mapache de arena.",extra:"Su personalidad es agresiva y burlona, y est\u00e1 ligado a Gaara durante gran parte de la historia."},
  {t:"m",q:"\u00bfQu\u00e9 biju tiene forma de gato de dos colas?",o:["Matatabi", "Saiken", "Kokuo", "Gyuki"],a:0,exp:"Matatabi es la bestia de dos colas con forma de gato envuelto en llamas azules.",extra:"Su jinchuriki fue Yugito Nii, de la Aldea de la Nube."},
  {t:"m",q:"\u00bfQu\u00e9 biju comparte nombre con el protagonista de otra obra cl\u00e1sica china?",o:["Son Goku, el Cuatro Colas", "Kurama", "Isobu", "Chomei"],a:0,exp:"El Cuatro Colas se llama Son Goku.",extra:"Es un gui\u00f1o a Sun Wukong, la misma figura que inspir\u00f3 parcialmente a Goku de Dragon Ball y muchos elementos de fantas\u00eda asi\u00e1tica."},
  {t:"m",q:"\u00bfQu\u00e9 jinchuriki del Cuatro Colas pelea contra Kisame?",o:["Roshi", "Han", "Utakata", "Yagura"],a:0,exp:"Roshi fue el jinchuriki de Son Goku, el Cuatro Colas.",extra:"Su uso de lava refleja la conexi\u00f3n elemental de su bestia y su propio estilo de combate."},
  {t:"m",q:"\u00bfQu\u00e9 jinchuriki fue tambi\u00e9n Mizukage?",o:["Yagura", "Gaara", "Killer Bee", "Roshi"],a:0,exp:"Yagura fue jinchuriki del Tres Colas y tambi\u00e9n Mizukage.",extra:"Su control por manipulaci\u00f3n externa est\u00e1 ligado a la etapa sangrienta de Kirigakure."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Akatsuki us\u00f3 el nombre de Madara durante a\u00f1os?",o:["Obito", "Itachi", "Pain", "Kisame"],a:0,exp:"Obito se hizo pasar por Madara para manipular Akatsuki y el mundo ninja.",extra:"El nombre de Madara ten\u00eda tanto peso hist\u00f3rico que usarlo bastaba para sembrar miedo y credibilidad."},
  {t:"m",q:"\u00bfQui\u00e9n fue el sensei de Minato?",o:["Jiraiya", "Hiruzen", "Kakashi", "Tobirama"],a:0,exp:"Jiraiya fue maestro de Minato.",extra:"Esto conecta una l\u00ednea de maestros y disc\u00edpulos: Jiraiya, Minato, Kakashi, Naruto."},
  {t:"m",q:"\u00bfQui\u00e9n fue el sensei de Kakashi, Obito y Rin?",o:["Minato", "Jiraiya", "Hiruzen", "Tobirama"],a:0,exp:"Minato fue maestro del equipo de Kakashi, Obito y Rin.",extra:"El Equipo Minato es un espejo tr\u00e1gico del Equipo 7, con amistades rotas por guerra y manipulaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica incompleta desarrolla Naruto combinando clones y naturaleza de viento?",o:["Rasen Shuriken", "Chidori Nagashi", "Kirin", "Odama Rasengan"],a:0,exp:"Naruto desarrolla el Rasen Shuriken usando clones para manejar transformaci\u00f3n de forma y naturaleza.",extra:"La t\u00e9cnica era peligrosa incluso para Naruto al principio, porque da\u00f1aba tambi\u00e9n su propio brazo a nivel microsc\u00f3pico."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica de Sasuke invoca un rayo natural desde el cielo?",o:["Kirin", "Chidori", "Amaterasu", "Indra Arrow"],a:0,exp:"Kirin usa rayos naturales guiados por Sasuke para atacar a gran velocidad.",extra:"Sasuke la usa contra Itachi, aprovechando el clima generado por t\u00e9cnicas de fuego previas."},
  {t:"m",q:"\u00bfQu\u00e9 verdad descubre Sasuke tras matar a Itachi?",o:["Itachi proteg\u00eda Konoha y a Sasuke", "Itachi era un impostor", "Itachi odiaba a todo el clan", "Itachi trabajaba para Orochimaru"],a:0,exp:"Sasuke descubre que Itachi actu\u00f3 bajo \u00f3rdenes y sacrific\u00f3 todo para protegerlo.",extra:"La revelaci\u00f3n cambia el objetivo de Sasuke: su odio se desplaza de Itachi hacia Konoha y el sistema ninja."},
  {t:"m",q:"\u00bfQui\u00e9n le revela a Sasuke la verdad sobre Itachi?",o:["Obito", "Naruto", "Kakashi", "Danzo"],a:0,exp:"Obito le cuenta a Sasuke la verdad sobre Itachi tras su muerte.",extra:"Obito manipula esa verdad para orientar a Sasuke contra Konoha."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el equipo que Sasuke forma tras abandonar a Orochimaru?",o:["Hebi", "Taka", "Akatsuki Jr.", "Kirin"],a:0,exp:"Sasuke forma el equipo Hebi inicialmente para buscar a Itachi.",extra:"Despu\u00e9s de conocer la verdad sobre Itachi, el grupo cambia su nombre a Taka y su objetivo se vuelve destruir Konoha."},
  {t:"m",q:"\u00bfQui\u00e9nes integran el equipo de Sasuke junto a \u00e9l?",o:["Suigetsu, Karin y Jugo", "Sai, Yamato y Sakura", "Neji, Lee y Tenten", "Hidan, Kakuzu y Deidara"],a:0,exp:"Sasuke recluta a Suigetsu, Karin y Jugo.",extra:"Cada miembro tiene una conexi\u00f3n con Orochimaru o sus experimentos, lo que refuerza el ambiente oscuro del camino de Sasuke."},
  {t:"m",q:"\u00bfDe qu\u00e9 clan proviene Karin?",o:["Uzumaki", "Uchiha", "Hyuga", "Kaguya"],a:0,exp:"Karin pertenece al clan Uzumaki.",extra:"Su enorme vitalidad y habilidades sensoriales reflejan rasgos del clan Uzumaki, aunque su historia se desarrolla lejos de Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 habilidad especial tiene Jugo?",o:["Origen natural del sello maldito", "Byakugan", "Control de insectos", "Elemento madera"],a:0,exp:"Jugo posee una habilidad natural que inspir\u00f3 los sellos malditos de Orochimaru.",extra:"Su cuerpo absorbe energ\u00eda natural de forma inestable, causando transformaciones violentas."},
  {t:"m",q:"\u00bfQu\u00e9 personaje busca reunir las espadas de los Siete Espadachines?",o:["Suigetsu", "Kisame", "Zabuza", "Jugo"],a:0,exp:"Suigetsu quiere reunir las espadas legendarias de la Niebla.",extra:"Suigetsu es hermano de Mangetsu Hozuki, un prodigio asociado a los Siete Espadachines."},
  {t:"m",q:"\u00bfQu\u00e9 clan puede licuar su cuerpo como agua?",o:["Hozuki", "Uzumaki", "Kaguya", "Nara"],a:0,exp:"El clan Hozuki puede convertir su cuerpo en agua.",extra:"Suigetsu usa esta habilidad para resistir ataques f\u00edsicos y moverse de forma fluida, aunque es vulnerable al rayo."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa el Byakugo no In?",o:["Tsunade y Sakura", "Hinata y Neji", "Ino y Karin", "Kurenai y Anko"],a:0,exp:"Tsunade y Sakura usan el Sello Byakugo.",extra:"El sello almacena chakra durante a\u00f1os y permite liberar enormes reservas para curaci\u00f3n y fuerza."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica m\u00e9dica permite regeneraci\u00f3n extrema a Tsunade?",o:["Creaci\u00f3n Renacimiento", "Izanagi", "Rasengan m\u00e9dico", "Modo Sabio"],a:0,exp:"Tsunade usa Creaci\u00f3n Renacimiento para regenerar heridas graves.",extra:"La t\u00e9cnica acelera divisi\u00f3n celular, pero reduce su esperanza de vida por el coste biol\u00f3gico."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es especialista en genjutsu y maestra del Equipo 8?",o:["Kurenai Yuhi", "Anko Mitarashi", "Shizune", "Mei Terumi"],a:0,exp:"Kurenai Yuhi es especialista en genjutsu y lidera el Equipo 8.",extra:"Su equipo incluye a Hinata, Kiba y Shino, todos con habilidades fuertes de rastreo y percepci\u00f3n."},
  {t:"m",q:"\u00bfQui\u00e9n fue alumna de Orochimaru y examinadora en los Chunin?",o:["Anko Mitarashi", "Kurenai", "Shizune", "Tsunade"],a:0,exp:"Anko Mitarashi fue alumna de Orochimaru y examinadora en la segunda prueba.",extra:"Anko tambi\u00e9n porta un sello maldito, lo que muestra la marca traum\u00e1tica que Orochimaru dej\u00f3 en antiguos disc\u00edpulos."},
  {t:"m",q:"\u00bfQu\u00e9 prueba de los Ex\u00e1menes Chunin ocurre en el Bosque de la Muerte?",o:["Segunda prueba", "Primera prueba", "Final del torneo", "Prueba de campanas"],a:0,exp:"La segunda prueba ocurre en el Bosque de la Muerte.",extra:"Los equipos deben conseguir pergaminos del Cielo y la Tierra mientras sobreviven a enemigos, trampas y bestias."},
  {t:"m",q:"\u00bfQui\u00e9n es el examinador de la primera prueba Chunin?",o:["Ibiki Morino", "Anko Mitarashi", "Hayate Gekko", "Genma Shiranui"],a:0,exp:"Ibiki Morino dirige la primera prueba escrita.",extra:"La prueba eval\u00faa espionaje, presi\u00f3n psicol\u00f3gica y capacidad de tomar decisiones, no solo conocimiento."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de la Arena usa marionetas?",o:["Kankuro", "Gaara", "Temari", "Baki"],a:0,exp:"Kankuro usa marionetas de combate.",extra:"Su estilo evoluciona con marionetas cada vez m\u00e1s peligrosas, incluyendo algunas relacionadas con Sasori."},
  {t:"m",q:"\u00bfQu\u00e9 arma usa Temari?",o:["Abanico gigante", "Marioneta", "Espada corta", "Guada\u00f1a triple"],a:0,exp:"Temari usa un abanico gigante para t\u00e9cnicas de viento.",extra:"Su estilo combina ataques de \u00e1rea, control de distancia y an\u00e1lisis t\u00e1ctico, algo que impresiona a Shikamaru."},
  {t:"m",q:"\u00bfQu\u00e9 personaje abandona una pelea aunque podr\u00eda ganarla por pereza?",o:["Shikamaru", "Naruto", "Lee", "Kiba"],a:0,exp:"Shikamaru se rinde contra Temari en los Ex\u00e1menes Chunin pese a tener una estrategia ganadora.",extra:"La decisi\u00f3n muestra su personalidad: brillante pero poco interesado en el esfuerzo innecesario."},
  {t:"m",q:"\u00bfQui\u00e9n es promovido a chunin tras los ex\u00e1menes originales?",o:["Shikamaru", "Naruto", "Sasuke", "Neji"],a:0,exp:"Shikamaru es el \u00fanico promovido a chunin en esa etapa.",extra:"Aunque no gan\u00f3 todas sus batallas, demostr\u00f3 liderazgo, an\u00e1lisis y madurez t\u00e1ctica."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa una calabaza para transportar arena?",o:["Gaara", "Kankuro", "Temari", "Sasori"],a:0,exp:"Gaara lleva una calabaza llena de arena especial.",extra:"La arena puede protegerlo autom\u00e1ticamente y formar t\u00e9cnicas defensivas y ofensivas de gran escala."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica defensiva de Neji gira chakra alrededor de su cuerpo?",o:["Kaiten", "Chidori", "Rasengan", "Kirin"],a:0,exp:"Kaiten, o Rotaci\u00f3n, protege a Neji liberando chakra mientras gira.",extra:"Es una defensa absoluta del clan Hyuga que aprovecha la visi\u00f3n del Byakugan y el control de tenketsu."},
  {t:"m",q:"\u00bfQu\u00e9 personaje fue jinchuriki de Kurama antes de Kushina?",o:["Mito Uzumaki", "Tsunade", "Konan", "Kaguya"],a:0,exp:"Mito Uzumaki fue la primera jinchuriki de Kurama en Konoha.",extra:"Era esposa de Hashirama Senju y miembro del clan Uzumaki, famoso por sus t\u00e9cnicas de sellado."},
  {t:"m",q:"\u00bfQu\u00e9 clan era famoso por t\u00e9cnicas de sellado y gran vitalidad?",o:["Uzumaki", "Nara", "Yamanaka", "Aburame"],a:0,exp:"El clan Uzumaki era conocido por f\u016binjutsu y vitalidad extraordinaria.",extra:"La destrucci\u00f3n de Uzushiogakure se debi\u00f3 en parte al temor que otros pa\u00edses ten\u00edan de sus t\u00e9cnicas de sellado."},
  {t:"m",q:"\u00bfCu\u00e1l era la aldea del clan Uzumaki?",o:["Uzushiogakure", "Konohagakure", "Amegakure", "Kirigakure"],a:0,exp:"Uzushiogakure era la Aldea Oculta del Remolino, hogar del clan Uzumaki.",extra:"Su s\u00edmbolo de remolino permanece en los uniformes de Konoha como se\u00f1al de la antigua alianza entre ambas aldeas."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es conocido como el Colmillo Blanco de Konoha?",o:["Sakumo Hatake", "Kakashi Hatake", "Minato Namikaze", "Jiraiya"],a:0,exp:"Sakumo Hatake, padre de Kakashi, era conocido como el Colmillo Blanco.",extra:"Su tragedia influye en la visi\u00f3n temprana de Kakashi sobre reglas y misiones, antes de que Obito cambie su perspectiva."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki era compa\u00f1ero de Itachi?",o:["Kisame", "Deidara", "Hidan", "Sasori"],a:0,exp:"Kisame Hoshigaki era el compa\u00f1ero de Itachi en Akatsuki.",extra:"La dupla combina genjutsu, inteligencia y enorme poder de chakra, siendo una de las parejas m\u00e1s temibles de la organizaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de Akatsuki era compa\u00f1ero de Deidara antes de Tobi?",o:["Sasori", "Hidan", "Kakuzu", "Pain"],a:0,exp:"Sasori fue compa\u00f1ero de Deidara.",extra:"Su contraste art\u00edstico es famoso: Sasori cree en el arte eterno, Deidara en el arte como explosi\u00f3n moment\u00e1nea."},
  {t:"m",q:"\u00bfQu\u00e9 personaje dice \u201cel arte es una explosi\u00f3n\u201d?",o:["Deidara", "Sasori", "Kakuzu", "Hidan"],a:0,exp:"Deidara defiende que el arte es una explosi\u00f3n.",extra:"Su frase resume su filosof\u00eda est\u00e9tica: la belleza est\u00e1 en el instante fugaz de destrucci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 personaje considera que el arte debe ser eterno?",o:["Sasori", "Deidara", "Konan", "Kisame"],a:0,exp:"Sasori cree que el arte verdadero debe perdurar eternamente.",extra:"Por eso convierte cuerpos en marionetas, intentando congelar la vida en una forma permanente."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Deidara como \u00faltimo recurso suicida contra Sasuke?",o:["C0", "C1", "C2", "C4"],a:0,exp:"Deidara usa C0, convirti\u00e9ndose en una explosi\u00f3n gigante.",extra:"Sasuke sobrevive usando a Manda como escudo mediante invocaci\u00f3n, lo que muestra su sangre fr\u00eda y rapidez."},
  {t:"m",q:"\u00bfQu\u00e9 serpiente gigante muere por la explosi\u00f3n de Deidara?",o:["Manda", "Aoda", "Gamabunta", "Katsuyu"],a:0,exp:"Manda muere tras ser usado por Sasuke para escapar de C0.",extra:"Manda era la invocaci\u00f3n m\u00e1s temida de Orochimaru, y su muerte subraya lo extremo de la estrategia de Sasuke."},
  {t:"m",q:"\u00bfQu\u00e9 serpiente invoca Sasuke m\u00e1s adelante?",o:["Aoda", "Manda", "Garaga", "Katsuyu"],a:0,exp:"Sasuke invoca a Aoda despu\u00e9s de la muerte de Manda.",extra:"Aoda es mucho m\u00e1s respetuoso y leal que Manda, reflejando una relaci\u00f3n distinta con Sasuke."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa una m\u00e1scara naranja en espiral?",o:["Tobi", "Pain", "Kakuzu", "Zetsu"],a:0,exp:"Tobi usa una m\u00e1scara naranja en espiral durante buena parte de Shippuden.",extra:"El dise\u00f1o de la m\u00e1scara alude visualmente al Kamui y al misterio alrededor de su ojo Sharingan."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se hace pasar por el l\u00edder torpe de Akatsuki al principio?",o:["Tobi", "Pain", "Zetsu", "Kisame"],a:0,exp:"Tobi act\u00faa como un miembro torpe y c\u00f3mico al inicio.",extra:"Esa fachada oculta a Obito, uno de los manipuladores principales detr\u00e1s del conflicto mundial."},
  {t:"m",q:"\u00bfQu\u00e9 cuerpo de Pain usa habilidades gravitacionales?",o:["Camino Deva", "Camino Animal", "Camino Preta", "Camino Naraka"],a:0,exp:"El Camino Deva usa t\u00e9cnicas como Shinra Tensei y Bansho Tenin.",extra:"Es el cuerpo principal de Pain, usando el cad\u00e1ver de Yahiko, lo que tiene un peso emocional enorme para Nagato y Konan."},
  {t:"m",q:"\u00bfQu\u00e9 cuerpo de Pain invoca criaturas?",o:["Camino Animal", "Camino Deva", "Camino Asura", "Camino Humano"],a:0,exp:"El Camino Animal se especializa en invocaciones.",extra:"Sus criaturas comparten visi\u00f3n mediante el Rinnegan, haciendo muy dif\u00edcil enfrentarlas sin entender el secreto de Pain."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica revive a los muertos a cambio de la vida del usuario del Rinnegan?",o:["Rinne Tensei", "Edo Tensei", "Izanagi", "Chibaku Tensei"],a:0,exp:"Rinne Tensei permite revivir muertos, pero normalmente cuesta la vida del usuario.",extra:"Nagato la usa para revivir a los habitantes de Konoha tras ser convencido por Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica crea una esfera gravitacional que atrae todo alrededor?",o:["Chibaku Tensei", "Shinra Tensei", "Kamui", "Kirin"],a:0,exp:"Chibaku Tensei crea un n\u00facleo gravitacional que atrae materia para formar una prisi\u00f3n.",extra:"Es una t\u00e9cnica asociada al Rinnegan y recuerda al m\u00e9todo usado para sellar al Diez Colas y crear la luna."},
  {t:"m",q:"\u00bfQu\u00e9 personaje convence a Nagato de cambiar su decisi\u00f3n final?",o:["Naruto", "Konan", "Jiraiya", "Kakashi"],a:0,exp:"Naruto convence a Nagato al responder a su visi\u00f3n del dolor sin rendirse al odio.",extra:"Naruto no ofrece una soluci\u00f3n f\u00e1cil, pero hereda la voluntad de Jiraiya y se compromete a romper el ciclo de odio."},
  {t:"m",q:"\u00bfQu\u00e9 frase es central en la filosof\u00eda de Pain?",o:["El dolor ense\u00f1a la paz", "La juventud arde", "Nunca abandono a mis amigos", "Ser Hokage es mi sue\u00f1o"],a:0,exp:"Pain cree que el dolor compartido puede obligar al mundo a entender la paz.",extra:"Su filosof\u00eda nace de guerras reales sufridas por aldeas peque\u00f1as como Amegakure, atrapadas entre grandes potencias."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Konan contra Obito con millones de explosivos?",o:["Oc\u00e9ano de papel explosivo", "Amaterasu", "Chibaku Tensei", "Kirin"],a:0,exp:"Konan prepara un ataque con una cantidad masiva de papeles explosivos contra Obito.",extra:"Su estrategia est\u00e1 dise\u00f1ada espec\u00edficamente para superar el l\u00edmite temporal de Kamui, mostrando cu\u00e1nto hab\u00eda estudiado a su enemigo."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Obito para sobrevivir al ataque de Konan?",o:["Izanagi", "Izanami", "Kotoamatsukami", "Susanoo"],a:0,exp:"Obito usa Izanagi para alterar su muerte y sobrevivir.",extra:"La supervivencia tiene un coste: pierde la luz de un Sharingan, pero logra recuperar el Rinnegan de Nagato."},
  {t:"m",q:"\u00bfQu\u00e9 ninja de Konoha se especializa en tortura e interrogatorio?",o:["Ibiki Morino", "Ebisu", "Genma", "Aoba"],a:0,exp:"Ibiki Morino es especialista en interrogatorio y tortura psicol\u00f3gica.",extra:"Su presencia en la primera prueba Chunin demuestra que la mente es tan importante como la fuerza en el mundo ninja."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa cuervos en sus t\u00e9cnicas e ilusiones?",o:["Itachi", "Kisame", "Deidara", "Hidan"],a:0,exp:"Itachi usa cuervos como parte de sus genjutsu, sustituciones y simbolismo visual.",extra:"Los cuervos refuerzan su imagen de misterio, vigilancia y tragedia."},
  {t:"m",q:"\u00bfQu\u00e9 elemento avanzado combina tierra y agua?",o:["Madera", "Hielo", "Lava", "Magnetismo"],a:0,exp:"El elemento madera combina tierra y agua.",extra:"Mokuton es famoso por Hashirama y es especialmente efectivo para controlar bestias con cola."},
  {t:"m",q:"\u00bfQu\u00e9 elemento avanzado combina viento y agua?",o:["Hielo", "Madera", "Lava", "Polvo"],a:0,exp:"El elemento hielo combina viento y agua.",extra:"Haku es el usuario m\u00e1s conocido de este kekkei genkai en la historia principal."},
  {t:"m",q:"\u00bfQu\u00e9 kekkei tota usa Onoki?",o:["Elemento Polvo", "Elemento Hielo", "Elemento Madera", "Elemento Lava"],a:0,exp:"Onoki usa Jinton, o Elemento Polvo.",extra:"Es un kekkei tota, combinaci\u00f3n de tres naturalezas, capaz de desintegrar objetivos a nivel molecular."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es la Quinta Mizukage?",o:["Mei Terumi", "Tsunade", "Konan", "Kurotsuchi"],a:0,exp:"Mei Terumi es la Quinta Mizukage.",extra:"Posee varios kekkei genkai, incluyendo lava y vapor, y ayuda a reformar Kirigakure tras su \u00e9poca sangrienta."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se convierte en Cuarta Tsuchikage?",o:["Kurotsuchi", "Mei", "Temari", "Karui"],a:0,exp:"Kurotsuchi se convierte en Tsuchikage en la era posterior.",extra:"Es nieta de Onoki y representa la nueva generaci\u00f3n de liderazgo en Iwagakure."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se convierte en Quinto Kazekage?",o:["Gaara", "Rasa", "Kankuro", "Baki"],a:0,exp:"Gaara se convierte en el Quinto Kazekage.",extra:"Su ascenso es uno de los grandes s\u00edmbolos de redenci\u00f3n de Naruto: de ni\u00f1o temido a l\u00edder admirado."},
  {t:"m",q:"\u00bfQui\u00e9n fue el padre de Gaara?",o:["Rasa", "Baki", "Yashamaru", "Onoki"],a:0,exp:"Rasa, el Cuarto Kazekage, fue padre de Gaara.",extra:"Rasa intent\u00f3 usar a Gaara como arma y orden\u00f3 pruebas crueles contra \u00e9l, causando gran parte de su trauma."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00edo de Gaara fue usado para quebrarlo emocionalmente?",o:["Yashamaru", "Baki", "Kankuro", "Chiyo"],a:0,exp:"Yashamaru fue manipulado para intentar matar a Gaara y da\u00f1arlo emocionalmente.",extra:"La mentira de que Yashamaru lo odiaba marc\u00f3 profundamente a Gaara y reforz\u00f3 su aislamiento."},
  {t:"m",q:"\u00bfQu\u00e9 anciana de la Arena revive a Gaara?",o:["Chiyo", "Tsunade", "Kurenai", "Mito"],a:0,exp:"Chiyo sacrifica su vida para revivir a Gaara.",extra:"Su acto cierra parte de la culpa de la generaci\u00f3n antigua de la Arena y permite que Gaara siga como Kazekage."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica de Chiyo puede dar vida a cambio de la propia?",o:["Tensei Ninjutsu", "Rinne Tensei", "Edo Tensei", "Byakugo"],a:0,exp:"Chiyo usa una t\u00e9cnica de transferencia de vida para revivir a Gaara.",extra:"Originalmente pensada para marionetas, la t\u00e9cnica se convierte en un sacrificio humano real."},
  {t:"m",q:"\u00bfQu\u00e9 espada usa Sasuke asociada a Orochimaru?",o:["Kusanagi", "Samehada", "Kubikiribocho", "Hiramekarei"],a:0,exp:"Sasuke usa una espada Kusanagi.",extra:"La espada refuerza su estilo m\u00e1s fr\u00edo y preciso durante Shippuden, lejos del combate impulsivo de Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Sasuke para cambiar de lugar con objetos o personas usando su Rinnegan?",o:["Amenotejikara", "Kamui", "Hiraishin", "Shunshin"],a:0,exp:"Sasuke usa Amenotejikara para intercambiar posiciones instant\u00e1neamente.",extra:"Esta habilidad vuelve sus combates extremadamente t\u00e1cticos, especialmente contra Madara, Kaguya y Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa el apodo \u201cCopy Ninja\u201d?",o:["Kakashi", "Itachi", "Sasuke", "Yamato"],a:0,exp:"Kakashi es conocido como el Ninja Copia.",extra:"Gracias a su Sharingan, copi\u00f3 m\u00e1s de mil t\u00e9cnicas, ganando fama internacional."},
  {t:"m",q:"\u00bfQu\u00e9 libro suele leer Kakashi?",o:["Icha Icha", "Manual ANBU", "Cr\u00f3nicas de Konoha", "El camino del Hokage"],a:0,exp:"Kakashi suele leer la serie Icha Icha de Jiraiya.",extra:"El gag contrasta su imagen de ninja serio con su gusto por novelas adultas absurdamente populares."},
  {t:"m",q:"\u00bfQui\u00e9n escribe la saga de novelas Icha Icha?",o:["Jiraiya", "Kakashi", "Tsunade", "Naruto"],a:0,exp:"Jiraiya es autor de las novelas Icha Icha.",extra:"Aunque se presenta como pervertido, Jiraiya tambi\u00e9n es escritor, esp\u00eda, maestro y una figura tr\u00e1gica profundamente idealista."},
  {t:"m",q:"\u00bfQu\u00e9 nombre usa Jiraiya como t\u00edtulo legendario?",o:["Sabio Pervertido", "Dios Shinobi", "Colmillo Blanco", "Rel\u00e1mpago Amarillo"],a:0,exp:"Naruto llama a Jiraiya \u201cEro-sennin\u201d, traducido como Sabio Pervertido.",extra:"El apodo resume la mezcla de comedia y grandeza del personaje: rid\u00edculo en superficie, heroico en el fondo."},
  {t:"m",q:"\u00bfQu\u00e9 sapos ancianos ayudan a Jiraiya en Modo Sabio?",o:["Fukasaku y Shima", "Gamabunta y Gamakichi", "Pakkun y Akamaru", "Katsuyu y Manda"],a:0,exp:"Fukasaku y Shima ayudan a Jiraiya a entrar en Modo Sabio.",extra:"Como Jiraiya no domina completamente el modo, necesita fusionarse con ellos para estabilizar la energ\u00eda natural."},
  {t:"m",q:"\u00bfQu\u00e9 forma de Naruto aparece al cooperar completamente con Kurama?",o:["Modo Kurama", "Modo Sabio imperfecto", "Sello Maldito", "Susanoo"],a:0,exp:"Naruto alcanza el Modo Kurama al cooperar con la bestia de nueve colas.",extra:"Este modo marca una reconciliaci\u00f3n enorme: Kurama deja de ser solo una fuente de poder robado y se vuelve aliado."},
  {t:"m",q:"\u00bfQui\u00e9n ayuda a Naruto a enfrentarse al odio de Kurama en la isla tortuga?",o:["Killer Bee", "Jiraiya", "Gaara", "Iruka"],a:0,exp:"Killer Bee ayuda a Naruto a entrenar como jinchuriki.",extra:"Bee ya domina una relaci\u00f3n cooperativa con Gyuki, por eso es el gu\u00eda perfecto para Naruto."},
  {t:"m",q:"\u00bfQu\u00e9 aparici\u00f3n emocional ayuda a Naruto durante su lucha interna con Kurama?",o:["Kushina", "Sakura", "Hinata", "Tsunade"],a:0,exp:"Kushina aparece dentro del sello para ayudar a Naruto.",extra:"La conversaci\u00f3n entre Naruto y su madre revela la historia de su nacimiento y le da un cierre emocional que necesitaba desde ni\u00f1o."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se declara a Naruto durante el ataque de Pain?",o:["Hinata", "Sakura", "Ino", "Tenten"],a:0,exp:"Hinata se declara a Naruto mientras intenta protegerlo de Pain.",extra:"Aunque no puede derrotar a Pain, su acto de valent\u00eda impacta profundamente a Naruto y muestra cu\u00e1nto ha crecido desde su timidez inicial."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n de Naruto aparece cuando cree que Hinata fue asesinada por Pain?",o:["Forma de seis colas", "Modo Sabio perfecto", "Modo Kurama completo", "Modo Rikudou"],a:0,exp:"Naruto libera seis colas del chakra de Kurama tras ver caer a Hinata.",extra:"La escena muestra el peligro de su v\u00ednculo incompleto con Kurama antes de aprender a cooperar con \u00e9l."},
  {t:"m",q:"\u00bfQui\u00e9n detiene a Naruto cuando casi libera el sello completo de Kurama contra Pain?",o:["Minato", "Jiraiya", "Kushina", "Kakashi"],a:0,exp:"Minato aparece dentro del sello y detiene a Naruto.",extra:"Minato dej\u00f3 parte de su chakra para intervenir si Naruto estaba a punto de liberar completamente al Kyubi."},
  {t:"m",q:"\u00bfQu\u00e9 ojo de Kakashi puede enviar objetivos a otra dimensi\u00f3n?",o:["Mangekyo Sharingan con Kamui", "Byakugan", "Rinnegan", "Tenseigan"],a:0,exp:"El Mangekyo Sharingan de Kakashi usa Kamui.",extra:"Durante a\u00f1os Kakashi no conoce completamente el origen de ese poder, que est\u00e1 conectado al ojo de Obito."},
  {t:"m",q:"\u00bfQu\u00e9 personaje abre la Octava Puerta contra Madara?",o:["Might Guy", "Rock Lee", "Kakashi", "Neji"],a:0,exp:"Might Guy abre la Octava Puerta contra Madara.",extra:"Su ataque Night Guy casi mata a Madara y le gana el reconocimiento del propio villano como el mejor usuario de taijutsu."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica final usa Guy contra Madara?",o:["Night Guy", "Hirudora", "Asa Kujaku", "Konoha Senpu"],a:0,exp:"Night Guy es la t\u00e9cnica m\u00e1xima de Guy al abrir la Octava Puerta.",extra:"El ataque distorsiona el espacio por pura fuerza f\u00edsica, una de las demostraciones m\u00e1s extremas de taijutsu en la serie."},
  {t:"m",q:"\u00bfQui\u00e9n salva a Guy de morir completamente tras usar la Octava Puerta?",o:["Naruto", "Sakura", "Tsunade", "Kakashi"],a:0,exp:"Naruto usa el poder recibido de Hagoromo para impedir que Guy muera de inmediato.",extra:"Aunque Guy sobrevive, queda gravemente afectado f\u00edsicamente, mostrando que el coste de la Octava Puerta sigue siendo real."},
  {t:"m",q:"\u00bfQu\u00e9 personaje muere protegiendo a Naruto y Hinata en la guerra?",o:["Neji", "Kiba", "Shino", "Lee"],a:0,exp:"Neji muere protegiendo a Naruto y Hinata durante la guerra.",extra:"Su muerte cierra de forma amarga su arco sobre destino y libertad: elige libremente sacrificarse por otros."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Akatsuki fue originalmente el Mizukage controlado por Obito?",o:["Yagura", "Kisame", "Zabuza", "Mangetsu"],a:0,exp:"Yagura, el Cuarto Mizukage, fue manipulado durante la \u00e9poca sangrienta de Kirigakure.",extra:"Esto explica parte de la reputaci\u00f3n brutal de la Aldea de la Niebla y la influencia secreta de Obito."},
  {t:"m",q:"\u00bfQu\u00e9 ninja de Konoha usa tinta como arma?",o:["Sai", "Shino", "Kiba", "Yamato"],a:0,exp:"Sai usa dibujos de tinta que cobran vida.",extra:"Su t\u00e9cnica refleja su personalidad inicial: expresiva en apariencia, pero emocionalmente vac\u00eda hasta que aprende v\u00ednculos reales."},
  {t:"m",q:"\u00bfQu\u00e9 organizaci\u00f3n entren\u00f3 a Sai desde ni\u00f1o?",o:["Ra\u00edz", "Akatsuki", "ANBU Niebla", "Siete Espadachines"],a:0,exp:"Sai fue criado por Ra\u00edz, una rama secreta dirigida por Danzo.",extra:"Ra\u00edz eliminaba emociones y nombres para crear herramientas perfectas, algo que Sai debe desaprender."},
  {t:"m",q:"\u00bfQu\u00e9 nombre ten\u00eda el hermano emocional de Sai?",o:["Shin", "Yamato", "Kabuto", "Torune"],a:0,exp:"Sai consideraba a Shin como su hermano.",extra:"Aunque no eran hermanos biol\u00f3gicos, su v\u00ednculo fue una de las pocas relaciones reales que Sai tuvo antes del Equipo 7."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Ra\u00edz usa insectos venenosos microsc\u00f3picos?",o:["Torune", "Fu", "Sai", "Yamato"],a:0,exp:"Torune Aburame usa insectos venenosos extremadamente peligrosos.",extra:"Su habilidad lo hace letal incluso por contacto, una variante oscura del estilo Aburame."},
  {t:"m",q:"\u00bfQui\u00e9n acompa\u00f1a a Danzo como guardaespaldas junto a Torune?",o:["Fu Yamanaka", "Sai", "Kabuto", "Ao"],a:0,exp:"Fu Yamanaka acompa\u00f1a a Danzo junto a Torune.",extra:"Fu usa t\u00e9cnicas del clan Yamanaka, reforzando c\u00f3mo Danzo reun\u00eda habilidades especiales de varios clanes."},
  {t:"m",q:"\u00bfQu\u00e9 samur\u00e1i lidera el Pa\u00eds del Hierro?",o:["Mifune", "Hanzo", "Darui", "Chojuro"],a:0,exp:"Mifune lidera a los samur\u00e1is del Pa\u00eds del Hierro.",extra:"El Pa\u00eds del Hierro es neutral y sirve como sede de la Cumbre de los Cinco Kage."},
  {t:"m",q:"\u00bfQu\u00e9 reuni\u00f3n es atacada por Sasuke tras la verdad de Itachi?",o:["Cumbre de los Cinco Kage", "Examen Chunin", "Consejo de Konoha", "Funeral de Jiraiya"],a:0,exp:"Sasuke ataca la Cumbre de los Cinco Kage.",extra:"Ese ataque muestra lo lejos que ha ca\u00eddo en su espiral de odio tras conocer la verdad sobre Itachi."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se convierte en mano derecha de Naruto como Hokage?",o:["Shikamaru", "Sasuke", "Kakashi", "Sai"],a:0,exp:"Shikamaru trabaja como asesor cercano de Naruto cuando este es Hokage.",extra:"Su inteligencia estrat\u00e9gica compensa la impulsividad de Naruto y mantiene continuidad pol\u00edtica en Konoha."},
  {t:"m",q:"\u00bfQu\u00e9 personaje suele decir que todo es \u201cproblem\u00e1tico\u201d?",o:["Shikamaru", "Naruto", "Kiba", "Choji"],a:0,exp:"Shikamaru es famoso por llamar problem\u00e1ticas a las situaciones dif\u00edciles.",extra:"Su pereza no impide que sea uno de los ninjas m\u00e1s inteligentes de su generaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 pieza de shogi simboliza para Asuma la pr\u00f3xima generaci\u00f3n?",o:["El rey", "El pe\u00f3n", "El caballo", "La torre"],a:0,exp:"Asuma ense\u00f1a que el rey representa a la pr\u00f3xima generaci\u00f3n de Konoha.",extra:"Shikamaru comprende esta lecci\u00f3n tras la muerte de Asuma, especialmente por el futuro hijo de su maestro."},
  {t:"m",q:"\u00bfQui\u00e9n es la pareja de Asuma?",o:["Kurenai", "Anko", "Shizune", "Tsunade"],a:0,exp:"Kurenai es la pareja de Asuma.",extra:"Tras la muerte de Asuma, Kurenai queda embarazada de su hija, Mirai Sarutobi."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la hija de Asuma y Kurenai?",o:["Mirai", "Sarada", "Sumire", "Chocho"],a:0,exp:"La hija de Asuma y Kurenai se llama Mirai Sarutobi.",extra:"Mirai representa literalmente la pr\u00f3xima generaci\u00f3n que Asuma quer\u00eda proteger."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es hijo del Tercer Hokage?",o:["Asuma Sarutobi", "Iruka Umino", "Kakashi Hatake", "Might Guy"],a:0,exp:"Asuma es hijo de Hiruzen Sarutobi, el Tercer Hokage.",extra:"Su relaci\u00f3n con su padre fue complicada, pero Asuma termina heredando la voluntad de fuego de Konoha a su manera."},
  {t:"m",q:"\u00bfQu\u00e9 ideal representa la Voluntad de Fuego?",o:["Proteger a la pr\u00f3xima generaci\u00f3n y la aldea", "Buscar poder individual", "Vengar al clan", "Dominar a otras aldeas"],a:0,exp:"La Voluntad de Fuego sostiene que la aldea es una familia y debe protegerse a las futuras generaciones.",extra:"Es el ideal central de Konoha, aunque la serie tambi\u00e9n muestra c\u00f3mo puede deformarse cuando se usa para justificar decisiones oscuras."},
  {t:"m",q:"\u00bfQu\u00e9 personaje fund\u00f3 Ra\u00edz?",o:["Danzo Shimura", "Hiruzen Sarutobi", "Tobirama Senju", "Orochimaru"],a:0,exp:"Danzo fund\u00f3 y dirigi\u00f3 Ra\u00edz como una rama secreta de ANBU.",extra:"Ra\u00edz actuaba sin emociones ni identidad p\u00fablica, representando el lado m\u00e1s sombr\u00edo de la seguridad de Konoha."},
  {t:"m",q:"\u00bfQu\u00e9 grupo de \u00e9lite usa m\u00e1scaras animales?",o:["ANBU", "Akatsuki", "Sannin", "Kage"],a:0,exp:"Los ANBU usan m\u00e1scaras y realizan misiones especiales de alto riesgo.",extra:"Kakashi e Itachi pertenecieron a ANBU, lo que refuerza sus pasados como prodigios sometidos a violencia desde j\u00f3venes."},
  {t:"m",q:"\u00bfQu\u00e9 animal aparece en la m\u00e1scara ANBU de Kakashi en varias representaciones?",o:["Perro", "Gato", "Zorro", "Halc\u00f3n"],a:0,exp:"Kakashi suele ser asociado con una m\u00e1scara ANBU de perro.",extra:"El motivo canino encaja con sus invocaciones de perros ninja y su estilo rastreador."},
  {t:"m",q:"\u00bfQu\u00e9 personaje del Equipo Guy usa muchas armas ninja?",o:["Tenten", "Neji", "Lee", "Hinata"],a:0,exp:"Tenten se especializa en invocar y usar armas ninja.",extra:"Aunque tiene menos foco narrativo que sus compa\u00f1eros, representa una especializaci\u00f3n cl\u00e1sica de herramientas y precisi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 personaje del Equipo 8 est\u00e1 enamorada de Naruto desde ni\u00f1a?",o:["Hinata", "Ino", "Tenten", "Sakura"],a:0,exp:"Hinata admira y ama a Naruto desde que eran ni\u00f1os.",extra:"Naruto inspira a Hinata a no rendirse, especialmente en su lucha contra Neji durante los Ex\u00e1menes Chunin."},
  {t:"m",q:"\u00bfQu\u00e9 personaje del Equipo 10 estaba enamorada de Sasuke al inicio?",o:["Ino", "Hinata", "Tenten", "Temari"],a:0,exp:"Ino estaba enamorada de Sasuke durante la primera parte.",extra:"Su rivalidad con Sakura nace en parte por Sasuke, aunque su amistad tiene ra\u00edces m\u00e1s profundas."},
  {t:"m",q:"\u00bfQu\u00e9 personaje era amiga de Sakura antes de su rivalidad?",o:["Ino", "Hinata", "Tenten", "Karin"],a:0,exp:"Ino fue amiga de Sakura y la ayud\u00f3 a ganar confianza de ni\u00f1a.",extra:"La rivalidad entre ambas es m\u00e1s compleja que una simple competencia rom\u00e1ntica: tambi\u00e9n trata de autoestima y crecimiento."},
  {t:"m",q:"\u00bfQu\u00e9 s\u00edmbolo aparece en la frente de Sakura tras dominar el Byakugo?",o:["Rombo violeta", "Marca Uchiha", "Sello espiral", "L\u00ednea Hyuga"],a:0,exp:"Sakura desarrolla un rombo violeta en la frente al completar el Sello Byakugo.",extra:"Ese s\u00edmbolo indica que ha acumulado suficiente chakra para usar t\u00e9cnicas avanzadas de Tsunade."},
  {t:"m",q:"\u00bfQu\u00e9 personaje corta su cabello durante los Ex\u00e1menes Chunin como se\u00f1al de determinaci\u00f3n?",o:["Sakura", "Ino", "Hinata", "Tenten"],a:0,exp:"Sakura corta su cabello durante el ataque de los ninjas del Sonido.",extra:"La escena simboliza que Sakura deja de depender solo de Sasuke y Naruto y empieza a luchar por s\u00ed misma."},
  {t:"m",q:"\u00bfQu\u00e9 aldea produce a los Cuatro del Sonido?",o:["Aldea del Sonido", "Aldea de la Niebla", "Aldea de la Lluvia", "Aldea de la Roca"],a:0,exp:"Los Cuatro del Sonido sirven a Orochimaru desde Otogakure.",extra:"Otogakure es una aldea creada por Orochimaru como fachada para sus experimentos y ambiciones."},
  {t:"m",q:"\u00bfQui\u00e9n funda la Aldea del Sonido?",o:["Orochimaru", "Kabuto", "Danzo", "Sasuke"],a:0,exp:"Orochimaru funda Otogakure, la Aldea Oculta del Sonido.",extra:"M\u00e1s que una aldea tradicional, funciona como base de investigaci\u00f3n, reclutamiento y experimentaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 subordinada de Orochimaru usa una flauta en combate?",o:["Tayuya", "Karin", "Kin", "Anko"],a:0,exp:"Tayuya usa una flauta para controlar invocaciones y genjutsu sonoro.",extra:"Su pelea contra Shikamaru destaca porque combina estrategia, sonido y control de campo."},
  {t:"m",q:"\u00bfQui\u00e9n derrota a Tayuya?",o:["Temari", "Shikamaru", "Ino", "Sakura"],a:0,exp:"Temari derrota a Tayuya tras llegar como refuerzo de la Arena.",extra:"Shikamaru la hab\u00eda contenido con estrategia, pero Temari aporta el poder ofensivo necesario para terminar la pelea."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de los Cuatro del Sonido usa telara\u00f1as?",o:["Kidomaru", "Jirobo", "Sakon", "Tayuya"],a:0,exp:"Kidomaru usa t\u00e9cnicas parecidas a telara\u00f1as y combate a distancia.",extra:"Su pelea contra Neji explota el punto ciego del Byakugan y obliga a Neji a ir m\u00e1s all\u00e1 de sus l\u00edmites."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de los Cuatro del Sonido combate a Choji?",o:["Jirobo", "Kidomaru", "Sakon", "Tayuya"],a:0,exp:"Jirobo enfrenta a Choji durante la misi\u00f3n de recuperaci\u00f3n de Sasuke.",extra:"La pelea es importante porque Choji demuestra que su amabilidad no es debilidad."},
  {t:"m",q:"\u00bfQu\u00e9 miembros de los Cuatro del Sonido comparten cuerpo?",o:["Sakon y Ukon", "Jirobo y Kidomaru", "Tayuya y Kin", "Dosu y Zaku"],a:0,exp:"Sakon y Ukon poseen una habilidad que les permite compartir y fusionar cuerpos.",extra:"Su estilo es especialmente peligroso en combate cuerpo a cuerpo, y Kiba debe arriesgarse mucho para enfrentarlos."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de la Arena ayuda a Kiba contra Sakon y Ukon?",o:["Kankuro", "Gaara", "Temari", "Baki"],a:0,exp:"Kankuro llega como refuerzo y ayuda a derrotar a Sakon y Ukon.",extra:"La llegada de los ninjas de la Arena muestra la nueva alianza entre Suna y Konoha tras la invasi\u00f3n."},
];

export default narutoQuestions;
